def advisor_provider_kind(provider: str) -> str:
    if provider == "anthropic":
        return "anthropic"
    if provider in ("ollama", "ollama-cloud"):
        return "ollama"
    if provider in ("lm-studio", "nvidia-hosted"):
        return "openai-compatible"
    return ""


