def openai_chat_to_anthropic(data: dict[str, Any], model: str, source_body: dict[str, Any] | None = None) -> dict[str, Any]:
    choice = {}
    choices = data.get("choices")
    if isinstance(choices, list) and choices:
        choice = choices[0] if isinstance(choices[0], dict) else {}
    message = choice.get("message") if isinstance(choice.get("message"), dict) else {}
    wrapped = {
        "message": {
            "content": message.get("content") or "",
            "tool_calls": message.get("tool_calls") or [],
        },
        "done_reason": "length" if choice.get("finish_reason") == "length" else "stop",
    }
    usage = data.get("usage") if isinstance(data.get("usage"), dict) else {}
    wrapped["prompt_eval_count"] = positive_int(usage.get("prompt_tokens")) or (estimate_tokens(source_body) if isinstance(source_body, dict) else 0)
    wrapped["eval_count"] = positive_int(usage.get("completion_tokens")) or 0
    out = ollama_chat_to_anthropic(wrapped, model, source_body=source_body)
    thinking_block = openai_reasoning_to_anthropic_thinking_block(message.get("reasoning_content"))
    if thinking_block is None:
        return out
    content = out.get("content")
    if not isinstance(content, list):
        content = [{"type": "text", "text": anthropic_content_to_text(content)}]
    out = dict(out)
    out["content"] = [thinking_block] + content
    return out


def openai_responses_to_anthropic_messages(body: dict[str, Any], fallback_model: str) -> dict[str, Any]:
    adapter = PROTOCOL_ADAPTERS.create("openai_responses", fallback_model=fallback_model)
    return dict(adapter.normalize_request(body))


def anthropic_message_to_openai_response(
    message: dict[str, Any], source_body: dict[str, Any] | None = None
) -> dict[str, Any]:
    adapter = PROTOCOL_ADAPTERS.create("openai_responses", source_body=source_body)
    return dict(adapter.normalize_response(message))


def write_openai_responses_response(
    handler: BaseHTTPRequestHandler,
    message: dict[str, Any],
    source_body: dict[str, Any] | None = None,
    *,
    stream: bool = True,
) -> None:
    response = anthropic_message_to_openai_response(message, source_body=source_body)
    if not stream:
        write_json(handler, response)
        return
    handler.send_response(200)
    handler.send_header("content-type", "text/event-stream")
    handler.send_header("cache-control", "no-cache")
    handler.send_header("connection", "close")
    handler.end_headers()

    def emit(event_name: str, payload: dict[str, Any]) -> None:
        handler.wfile.write(f"event: {event_name}\ndata: {json.dumps(payload, ensure_ascii=False)}\n\n".encode())

    created = {**response, "status": "in_progress", "output": []}
    emit("response.created", {"type": "response.created", "response": created})
    for output_index, item in enumerate(response.get("output") or []):
        item_added = {**item}
        if item_added.get("type") == "message":
            item_added["content"] = []
        emit(
            "response.output_item.added",
            {
                "type": "response.output_item.added",
                "response_id": response["id"],
                "output_index": output_index,
                "item": item_added,
            },
        )
        if item.get("type") == "message":
            content = item.get("content") if isinstance(item.get("content"), list) else []
            for content_index, part in enumerate(content):
                if not isinstance(part, dict) or part.get("type") != "output_text":
                    continue
                empty_part = {**part, "text": ""}
                emit(
                    "response.content_part.added",
                    {
                        "type": "response.content_part.added",
                        "response_id": response["id"],
                        "item_id": item["id"],
                        "output_index": output_index,
                        "content_index": content_index,
                        "part": empty_part,
                    },
                )
                text = str(part.get("text") or "")
                if text:
                    emit(
                        "response.output_text.delta",
                        {
                            "type": "response.output_text.delta",
                            "response_id": response["id"],
                            "item_id": item["id"],
                            "output_index": output_index,
                            "content_index": content_index,
                            "delta": text,
                        },
                    )
                emit(
                    "response.output_text.done",
                    {
                        "type": "response.output_text.done",
                        "response_id": response["id"],
                        "item_id": item["id"],
                        "output_index": output_index,
                        "content_index": content_index,
                        "text": text,
                    },
                )
                emit(
                    "response.content_part.done",
                    {
                        "type": "response.content_part.done",
                        "response_id": response["id"],
                        "item_id": item["id"],
                        "output_index": output_index,
                        "content_index": content_index,
                        "part": part,
                    },
                )
        emit(
            "response.output_item.done",
            {
                "type": "response.output_item.done",
                "response_id": response["id"],
                "output_index": output_index,
                "item": item,
            },
        )
    emit("response.completed", {"type": "response.completed", "response": response})
    handler.wfile.flush()


def write_openai_responses_error(handler: BaseHTTPRequestHandler, message: str, *, stream: bool = True, status: int = 500) -> None:
    payload = {"type": "error", "error": {"type": "api_error", "message": message}}
    if not stream:
        write_json(handler, payload, status)
        return
    handler.send_response(status)
    handler.send_header("content-type", "text/event-stream")
    handler.send_header("cache-control", "no-cache")
    handler.send_header("connection", "close")
    handler.end_headers()
    handler.wfile.write(f"event: error\ndata: {json.dumps(payload, ensure_ascii=False)}\n\n".encode())
    handler.wfile.flush()


