def collect_ollama_message_for_responses(
    handler: BaseHTTPRequestHandler,
    provider: str,
    pcfg: dict[str, Any],
    body: dict[str, Any],
) -> dict[str, Any]:
    body = normalize_thinking_for_non_anthropic_provider(provider, pcfg, body)
    model = resolve_requested_model(provider, pcfg, body.get("model"))
    original_body = body
    upstream_body = body_with_advisor_tool(body, pcfg) if advisor_provider_supported(provider) else body
    req_body = ollama_chat_request(model, upstream_body, pcfg, stream=False)
    url = provider_endpoint(provider, pcfg, "ollama_chat")
    compatibility_test = str(handler.headers.get(COMPATIBILITY_TEST_HEADER) or "").strip().lower() in ("1", "true", "yes", "on")
    if compatibility_test:
        waited, rpm_used, rpm_limit = 0.0, 0, router_rate_limit_effective_rpm(provider, pcfg, model)
    else:
        waited, rpm_used, rpm_limit = apply_router_rate_limit(provider, pcfg, model)
    data = post_json_with_rate_retry(
        url,
        req_body,
        provider_headers(provider, pcfg, handler.headers),
        ollama_request_timeout_seconds(pcfg),
        provider,
        pcfg,
        model,
        None,
        retry_rate_limits=not compatibility_test,
    )
    message = ollama_chat_to_anthropic(data, model, source_body=original_body)
    message = refine_message_with_advisor(provider, pcfg, original_body, message, model)
    remember_channel_injected_tool_uses(original_body, message)
    return prepend_anthropic_text(message, rate_limit_notice(waited, rpm_used, rpm_limit, bool(pcfg.get("rate_limit_status", False))))


def collect_openai_chat_message_for_responses(
    handler: BaseHTTPRequestHandler,
    provider: str,
    pcfg: dict[str, Any],
    body: dict[str, Any],
) -> dict[str, Any]:
    body = normalize_thinking_for_non_anthropic_provider(provider, pcfg, body)
    model = resolve_requested_model(provider, pcfg, body.get("model"))
    if provider == "nvidia-hosted":
        model = ncp_model_id_for_nvidia_hosted(model)
    original_body = body
    upstream_body = body_with_advisor_tool(body, pcfg) if advisor_provider_supported(provider) else body
    url = provider_endpoint(provider, pcfg, "openai_chat")
    compatibility_test = str(handler.headers.get(COMPATIBILITY_TEST_HEADER) or "").strip().lower() in ("1", "true", "yes", "on")
    waited, rpm_used, rpm_limit = apply_router_rate_limit(provider, pcfg, model)
    req_body = openai_compatible_chat_request(provider, model, upstream_body, pcfg, stream=False)
    data = post_json_with_rate_retry(
        url,
        req_body,
        provider_headers(provider, pcfg, handler.headers),
        provider_request_timeout_seconds(pcfg),
        provider,
        pcfg,
        model,
        None,
        retry_rate_limits=not compatibility_test,
    )
    message = openai_chat_to_anthropic(data, model, source_body=original_body)
    message = refine_message_with_advisor(provider, pcfg, original_body, message, model)
    remember_channel_injected_tool_uses(original_body, message)
    return prepend_anthropic_text(message, rate_limit_notice(waited, rpm_used, rpm_limit, bool(pcfg.get("rate_limit_status", False))))


def collect_anthropic_message_for_responses(
    handler: BaseHTTPRequestHandler,
    provider: str,
    pcfg: dict[str, Any],
    body: dict[str, Any],
) -> dict[str, Any]:
    body = normalize_thinking_for_non_anthropic_provider(provider, pcfg, body)
    body = normalize_anthropic_system_role_messages(body)
    body = cap_anthropic_body_for_provider(provider, pcfg, body)
    body = apply_provider_request_options(provider, pcfg, body)
    body = rehydrate_suppressed_thinking_passback(provider, pcfg, body)
    upstream_model = resolve_requested_model(provider, pcfg, body.get("model"))
    if provider == "nvidia-hosted":
        upstream_model = ncp_model_id_for_nvidia_hosted(upstream_model)
    body["model"] = upstream_model
    body = resolve_tool_model_references(provider, pcfg, body)
    body = normalize_anthropic_model_request_options(provider, pcfg, body, upstream_model)
    upstream_body = body_without_ciel_runtime_internal_metadata({**body, "stream": False})
    base = native_anthropic_base_url(provider, pcfg) if provider_native_compat_enabled(provider, pcfg) else provider_upstream_request_base(provider, pcfg)
    url = join_url(base, "/v1/messages")
    upstream_query = upstream_messages_query(pcfg, handler.path, provider)
    if upstream_query:
        url = f"{url}?{upstream_query}"
    headers = provider_headers(provider, pcfg, handler.headers)
    for h in ("anthropic-beta", "anthropic-dangerous-direct-browser-access"):
        if handler.headers.get(h):
            headers[h] = handler.headers[h]
    waited, rpm_used, rpm_limit = apply_router_rate_limit(provider, pcfg, upstream_model)
    resp = open_provider_request_with_key_retry(
        url,
        upstream_body,
        headers,
        provider_request_timeout_seconds(pcfg),
        provider,
        pcfg,
        upstream_model,
        stream=False,
    )
    try:
        raw_resp = resp.read()
        payload = json.loads(raw_resp.decode("utf-8", errors="replace"))
        if not isinstance(payload, dict):
            raise RuntimeError("upstream returned non-object JSON")
        payload = normalize_response_thinking_for_non_anthropic_provider(provider, pcfg, payload, upstream_model)
        payload = append_synthetic_tasklist_to_message(payload, upstream_model, body, "native_json", provider=provider)
        return prepend_anthropic_text(payload, rate_limit_notice(waited, rpm_used, rpm_limit, bool(pcfg.get("rate_limit_status", False))))
    finally:
        try:
            resp.close()
        except Exception:
            pass


def collect_provider_message_for_responses(
    handler: BaseHTTPRequestHandler,
    provider: str,
    pcfg: dict[str, Any],
    body: dict[str, Any],
) -> dict[str, Any]:
    if provider in ("ollama", "ollama-cloud"):
        return collect_ollama_message_for_responses(handler, provider, pcfg, body)
    if provider in OPENCODE_PROVIDER_NAMES:
        upstream_model = resolve_requested_model(provider, pcfg, body.get("model"))
        endpoint_kind = opencode_endpoint_kind(provider, upstream_model, pcfg)
        if endpoint_kind == "openai-chat":
            return collect_openai_chat_message_for_responses(handler, provider, pcfg, body)
        if endpoint_kind not in ("anthropic-messages",):
            provider_label = PROVIDER_LABELS.get(provider, provider)
            raise RuntimeError(
                f"{provider_label} model {upstream_model!r} uses the {endpoint_kind} endpoint family. "
                f"ciel-runtime currently routes {provider_label} /v1/messages and /v1/chat/completions models."
            )
    if codex_openai_router_enabled(provider, pcfg):
        return collect_openai_chat_message_for_responses(handler, provider, pcfg, body)
    if provider_openai_router_enabled(provider, pcfg):
        return collect_openai_chat_message_for_responses(handler, provider, pcfg, body)
    return collect_anthropic_message_for_responses(handler, provider, pcfg, body)


def codex_routed_upstream_headers(pcfg: dict[str, Any], inbound_headers: Any | None = None) -> dict[str, str]:
    del pcfg
    headers: dict[str, str] = {}
    hop_by_hop = {
        "connection",
        "content-length",
        "host",
        "proxy-authenticate",
        "proxy-authorization",
        "te",
        "trailer",
        "transfer-encoding",
        "upgrade",
    }
    if inbound_headers is not None:
        for name, value in inbound_headers.items():
            low = str(name).lower()
            if low in hop_by_hop:
                continue
            if low == "accept-encoding":
                headers["accept-encoding"] = "identity"
                continue
            if low == "content-type":
                headers["content-type"] = str(value)
                continue
            if value:
                headers[str(name)] = str(value)
    if not any(str(k).lower() == "content-type" for k in headers):
        headers["content-type"] = "application/json"
    headers = with_upstream_user_agent(headers)
    if not any(str(k).lower() == "authorization" for k in headers):
        raise RuntimeError("Codex routed mode did not receive native Codex auth headers from the Codex CLI.")
    return headers


def codex_routed_auth_error_message(message: str) -> str:
    low = str(message or "").lower()
    if "api.responses.write" not in low and "insufficient permissions" not in low and "unauthorized" not in low:
        return message
    guidance = (
        " Codex routed is expected to forward Codex CLI native auth to the ChatGPT Codex backend. "
        "If this mentions api.responses.write, the request is still using the OpenAI Platform /v1 endpoint; "
        "upgrade ciel-runtime and relaunch Codex routed so the local base URL is /backend-api/codex."
    )
    return f"{message}{guidance}"


def _responses_input_as_list(value: Any) -> list[dict[str, Any]]:
    if isinstance(value, str):
        return [{"type": "message", "role": "user", "content": [{"type": "input_text", "text": value}]}]
    if isinstance(value, dict):
        return [dict(value)]
    if isinstance(value, list):
        return [dict(item) for item in value if isinstance(item, dict)]
    return []


def _responses_message_item(role: str, text: str) -> dict[str, Any]:
    role = role if role in ("user", "assistant", "system", "developer") else "user"
    text_type = "output_text" if role == "assistant" else "input_text"
    return {"type": "message", "role": role, "content": [{"type": text_type, "text": text}]}


def codex_responses_body_with_channel_context(body: dict[str, Any]) -> tuple[dict[str, Any], dict[str, Any]]:
    delivery_body = openai_responses_to_anthropic_messages(body, str(body.get("model") or ""))
    original_count = len(delivery_body.get("messages") or [])
    delivery_body = body_with_pending_channel_messages(delivery_body)
    delivery_body = body_with_channel_tool_result_context(delivery_body)
    messages = [m for m in delivery_body.get("messages") or [] if isinstance(m, dict)]
    additions = messages[original_count:]
    metadata = delivery_body.get("metadata") if isinstance(delivery_body.get("metadata"), dict) else {}
    out = dict(body)
    # ChatGPT Codex backend rejects metadata. Keep Ciel Runtime delivery cursors
    # in delivery_body only; do not forward them upstream.
    out.pop("metadata", None)
    if not additions and not metadata:
        return out, delivery_body
    input_items = _responses_input_as_list(body.get("input", []))
    for message in additions:
        text = anthropic_content_to_text(message.get("content"))
        if text.strip():
            input_items.append(_responses_message_item(str(message.get("role") or "user"), text))
    if input_items:
        out["input"] = input_items
    return out, delivery_body


def _copy_upstream_response_headers(handler: BaseHTTPRequestHandler, headers: Any) -> None:
    skipped = {"connection", "content-length", "transfer-encoding", "content-encoding"}
    try:
        items = headers.items()
    except Exception:
        items = []
    wrote_content_type = False
    for key, value in items:
        low = str(key).lower()
        if low in skipped:
            continue
        if low == "content-type":
            wrote_content_type = True
        handler.send_header(str(key), str(value))
    if not wrote_content_type:
        handler.send_header("content-type", "application/json")
    handler.send_header("connection", "close")


def codex_backend_upstream_url(request_path: str, query: str = "") -> str:
    parsed_path = urllib.parse.urlparse(request_path).path
    prefixes = ("/backend-api/codex", "/v1")
    suffix = parsed_path
    for prefix in prefixes:
        if parsed_path == prefix:
            suffix = ""
            break
        if parsed_path.startswith(prefix + "/"):
            suffix = parsed_path[len(prefix):]
            break
    url = join_url(CODEX_ROUTED_UPSTREAM_BASE, suffix)
    if query:
        url = f"{url}?{query}"
    return url


def forward_codex_backend_json(
    handler: BaseHTTPRequestHandler,
    provider: str,
    pcfg: dict[str, Any],
    body: dict[str, Any],
    *,
    mutate_responses: bool = False,
) -> dict[str, Any] | None:
    upstream_body = body
    delivery_body: dict[str, Any] | None = None
    if mutate_responses:
        upstream_body, delivery_body = codex_responses_body_with_channel_context(body)
        begin_pending_channel_delivery(handler, delivery_body)
    parsed = urllib.parse.urlparse(handler.path)
    url = codex_backend_upstream_url(parsed.path, parsed.query)
    headers = codex_routed_upstream_headers(pcfg, handler.headers)
    data = json.dumps(upstream_body).encode("utf-8")
    max_capacity_retries = codex_capacity_retry_limit() if mutate_responses else 0
    for attempt in range(max_capacity_retries + 1):
        req = urllib.request.Request(url, data=data, headers=headers, method="POST")
        with provider_urlopen(req, timeout=provider_request_timeout_seconds(pcfg), provider=provider, pcfg=pcfg) as resp:
            preamble = read_codex_response_preamble(resp) if mutate_responses else None
            if preamble is not None and preamble.capacity_error_code and attempt < max_capacity_retries:
                retry_no = attempt + 1
                wait = upstream_retry_wait_seconds(retry_no)
                model = str(upstream_body.get("model") or "")
                router_log(
                    "WARN",
                    "codex_capacity_retry model=%s attempt=%d/%d code=%s wait=%.2fs"
                    % (model, retry_no, max_capacity_retries, preamble.capacity_error_code, wait),
                )
                EVENT_BUS.publish(
                    level="warn",
                    category="router.retry",
                    message="Codex model capacity retry",
                    provider=provider,
                    model=model,
                    data={
                        "attempt": retry_no,
                        "total": max_capacity_retries,
                        "code": preamble.capacity_error_code,
                        "wait_seconds": wait,
                    },
                )
                time.sleep(wait)
                continue

            handler.send_response(getattr(resp, "status", 200))
            _copy_upstream_response_headers(handler, resp.headers)
            handler.end_headers()
            if preamble is not None and preamble.payload:
                handler.wfile.write(preamble.payload)
                handler.wfile.flush()
            while True:
                chunk = resp.read(65536)
                if not chunk:
                    break
                handler.wfile.write(chunk)
                handler.wfile.flush()
            break
    return delivery_body


def codex_capacity_retry_limit() -> int:
    raw = str(os.environ.get("CIEL_RUNTIME_CODEX_CAPACITY_RETRIES") or "3").strip()
    try:
        return max(0, min(10, int(raw)))
    except ValueError:
        return 3


def forward_codex_backend_get(handler: BaseHTTPRequestHandler, provider: str, pcfg: dict[str, Any]) -> None:
    parsed = urllib.parse.urlparse(handler.path)
    url = codex_backend_upstream_url(parsed.path, parsed.query)
    headers = codex_routed_upstream_headers(pcfg, handler.headers)
    req = urllib.request.Request(url, headers=headers, method="GET")
    with provider_urlopen(req, timeout=provider_request_timeout_seconds(pcfg), provider=provider, pcfg=pcfg) as resp:
        handler.send_response(getattr(resp, "status", 200))
        _copy_upstream_response_headers(handler, resp.headers)
        handler.end_headers()
        while True:
            chunk = resp.read(65536)
            if not chunk:
                break
            handler.wfile.write(chunk)
            handler.wfile.flush()


def forward_codex_responses(handler: BaseHTTPRequestHandler, provider: str, pcfg: dict[str, Any], body: dict[str, Any]) -> None:
    delivery_body = forward_codex_backend_json(handler, provider, pcfg, body, mutate_responses=True)
    if delivery_body is None:
        return
    mark_pending_channel_delivery_success(handler, "codex_responses_proxy")
    commit_pending_channel_delivery_cursors(delivery_body, handler)


def handle_openai_responses_post(
    handler: BaseHTTPRequestHandler,
    cfg: dict[str, Any],
    provider: str,
    pcfg: dict[str, Any],
    body: dict[str, Any],
) -> None:
    import_check_body = openai_responses_to_anthropic_messages(body, current_alias(cfg))
    if maybe_handle_import_session_request(
        handler,
        import_check_body,
        client_runtime="codex",
        response_format="openai",
        source_body=body,
    ):
        return
    if codex_routed_enabled(provider, pcfg):
        request_id = f"{os.getpid()}-{time.time_ns()}"
        EVENT_BUS.publish(
            level="info",
            category="router.request",
            message="Codex Responses request received",
            request_id=request_id,
            provider=provider,
            model=str(body.get("model") or ""),
            data={
                "path": urllib.parse.urlparse(handler.path).path,
                "input_items": len(_responses_input_as_list(body.get("input", []))),
                "tools": len(body.get("tools") or []),
            },
        )
        dump_request_for_trace(provider, urllib.parse.urlparse(handler.path).path, body)
        try:
            forward_codex_responses(handler, provider, pcfg, body)
        except urllib.error.HTTPError as exc:
            raw = exc.read().decode("utf-8", errors="ignore")
            mark_pending_channel_delivery_failed(handler, f"codex_responses_http_error:{exc.code}")
            message = upstream_http_error_message(exc, raw)
            if exc.code in (401, 403):
                message = codex_routed_auth_error_message(message)
            write_openai_responses_error(handler, message, stream=bool(body.get("stream", True)), status=exc.code)
        except Exception as exc:
            if is_client_disconnect_error(exc):
                mark_pending_channel_delivery_failed(handler, f"codex_responses_client_disconnected:{type(exc).__name__}")
                return
            mark_pending_channel_delivery_failed(handler, f"codex_responses_error:{type(exc).__name__}")
            write_openai_responses_error(handler, f"{type(exc).__name__}: {exc}", stream=bool(body.get("stream", True)))
        return
    stream = bool(body.get("stream", True))
    anthropic_body = import_check_body
    _update_tool_schema_registry(anthropic_body.get("tools"))
    anthropic_body = normalize_thinking_for_non_anthropic_provider(provider, pcfg, anthropic_body)
    request_id = f"{os.getpid()}-{time.time_ns()}"
    EVENT_BUS.publish(
        level="info",
        category="router.request",
        message="OpenAI Responses request received",
        request_id=request_id,
        provider=provider,
        model=str(anthropic_body.get("model") or ""),
        data={
            "path": "/v1/responses",
            "messages": len(anthropic_body.get("messages") or []),
            "tools": len(anthropic_body.get("tools") or []),
            **router_event_message_preview(anthropic_body, cfg),
        },
    )
    dump_request_for_trace(provider, "/v1/responses", body)
    anthropic_body = filter_blocked_tools(provider, pcfg, anthropic_body)
    anthropic_body = normalize_tool_choice_for_provider(provider, pcfg, anthropic_body)
    write_context_usage(provider, pcfg, anthropic_body, "responses")
    anthropic_body = strip_autonomous_advisor_server_tools(provider, anthropic_body)
    anthropic_body = body_with_pending_channel_messages(anthropic_body)
    anthropic_body = body_with_channel_tool_result_context(anthropic_body)
    begin_pending_channel_delivery(handler, anthropic_body)
    anthropic_body = normalize_request_for_provider_wire(provider, pcfg, anthropic_body)
    router_log(
        "DEBUG",
        f"POST /v1/responses provider={provider} model={anthropic_body.get('model')} "
        f"tools={len(anthropic_body.get('tools') or [])} msgs={len(anthropic_body.get('messages') or [])}",
    )
    try:
        message = collect_provider_message_for_responses(handler, provider, pcfg, anthropic_body)
        write_openai_responses_response(handler, message, source_body=body, stream=stream)
        mark_pending_channel_delivery_success(handler, "responses_json")
        commit_pending_channel_delivery_cursors(anthropic_body, handler)
    except urllib.error.HTTPError as exc:
        raw = exc.read().decode("utf-8", errors="ignore")
        mark_pending_channel_delivery_failed(handler, f"responses_http_error:{exc.code}")
        write_openai_responses_error(handler, upstream_http_error_message(exc, raw), stream=stream, status=exc.code)
    except Exception as exc:
        if is_client_disconnect_error(exc):
            mark_pending_channel_delivery_failed(handler, f"responses_client_disconnected:{type(exc).__name__}")
            return
        EVENT_BUS.publish(
            level="error",
            category="router.error",
            message=str(exc),
            request_id=request_id,
            provider=provider,
            model=str(anthropic_body.get("model") or ""),
            data={"error_type": type(exc).__name__},
        )
        mark_pending_channel_delivery_failed(handler, f"responses_error:{type(exc).__name__}")
        write_openai_responses_error(handler, f"{type(exc).__name__}: {exc}", stream=stream)


def handle_codex_backend_passthrough_post(
    handler: BaseHTTPRequestHandler,
    provider: str,
    pcfg: dict[str, Any],
    body: dict[str, Any],
) -> None:
    try:
        forward_codex_backend_json(handler, provider, pcfg, body, mutate_responses=False)
    except urllib.error.HTTPError as exc:
        raw = exc.read().decode("utf-8", errors="ignore")
        write_openai_responses_error(handler, upstream_http_error_message(exc, raw), stream=False, status=exc.code)
    except Exception as exc:
        if is_client_disconnect_error(exc):
            return
        write_openai_responses_error(handler, f"{type(exc).__name__}: {exc}", stream=False)


def handle_codex_backend_passthrough_get(handler: BaseHTTPRequestHandler, provider: str, pcfg: dict[str, Any]) -> None:
    try:
        forward_codex_backend_get(handler, provider, pcfg)
    except urllib.error.HTTPError as exc:
        raw = exc.read().decode("utf-8", errors="ignore")
        write_json(handler, {"error": {"message": upstream_http_error_message(exc, raw)}}, status=exc.code)
    except Exception as exc:
        if is_client_disconnect_error(exc):
            return
        write_json(handler, {"error": {"message": f"{type(exc).__name__}: {exc}"}}, status=502)


