def _channel_prompt_scalar(value: Any) -> Any:
    if value is None or isinstance(value, (bool, int, float)):
        return value
    if isinstance(value, str):
        text = value.strip()
        if not text or len(text) > 240:
            return None
        return text
    if isinstance(value, list):
        out: list[Any] = []
        for item in value[:10]:
            scalar = _channel_prompt_scalar(item)
            if scalar is not None:
                out.append(scalar)
        if not out:
            return None
        try:
            if len(json.dumps(out, ensure_ascii=False, separators=(",", ":"), default=str)) > 300:
                return None
        except Exception:
            return None
        return out
    return None


def _channel_prompt_metadata(message: dict[str, Any]) -> str:
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    if not meta:
        return ""
    prompt_meta: dict[str, Any] = {}
    for key in _CHANNEL_PROMPT_META_KEYS:
        if key not in meta or _metadata_key_is_sensitive(key):
            continue
        value = _channel_prompt_scalar(meta.get(key))
        if value is None:
            continue
        prompt_meta[key] = value
    if not prompt_meta:
        return ""
    kept: dict[str, Any] = {}
    for key, value in prompt_meta.items():
        candidate = dict(kept)
        candidate[key] = value
        text = json.dumps(candidate, ensure_ascii=False, separators=(",", ":"), default=str)
        if len(text) > 900:
            continue
        kept = candidate
    return json.dumps(kept, ensure_ascii=False, separators=(",", ":"), default=str) if kept else ""


def format_channel_wake_prompt(message: dict[str, Any]) -> str:
    channel = str(message.get("channel") or "default")
    sender = str(message.get("sender_id") or "channel")
    mid = str(message.get("id") or "")
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    room = str(meta.get("room_id") or meta.get("room") or channel)
    thread = str(message.get("thread_id") or meta.get("thread_id") or "")
    body = re.sub(r"\s+", " ", str(message.get("message") or "")).strip()
    fields = [f"channel={channel}", f"room={room}", f"from={sender}"]
    if mid:
        fields.append(f"id={mid}")
    if thread:
        fields.append(f"thread={thread}")
    prompt_meta = _channel_prompt_metadata(message)
    if prompt_meta:
        fields.append(f"metadata={prompt_meta}")
    return (
        "[ciel-runtime external channel message] "
        + " ".join(fields)
        + f" text={json.dumps(body, ensure_ascii=False)}"
    )

def _format_channel_web_chat_wake_item(message: dict[str, Any]) -> str:
    channel = str(message.get("channel") or "default")
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    reply_channel = str(meta.get("reply_channel") or channel)
    thread = str(message.get("thread_id") or meta.get("thread_id") or reply_channel)
    mid = str(message.get("id") or "")
    body = re.sub(r"\s+", " ", str(message.get("message") or "")).strip()
    fields = [f"id={mid}", f"channel={reply_channel}", f"thread={thread}"]
    return " ".join(field for field in fields if not field.endswith("=")) + f" user={json.dumps(body, ensure_ascii=False)}"


def format_channel_web_chat_wake_batch_prompt(messages: list[dict[str, Any]]) -> str:
    items = " ; ".join(_format_channel_web_chat_wake_item(message) for message in messages)
    count = len(messages)
    return f"[ciel-runtime web chat] {count} browser message(s): {items}"


def _channel_wake_message_noise_reason(message: dict[str, Any]) -> str | None:
    body = re.sub(r"\s+", " ", str(message.get("message") or "")).strip().lower()
    kind = str(message.get("kind") or "").strip().lower()
    if not body:
        return "empty"
    if kind in {"connection", "connected", "heartbeat", "keepalive"}:
        return kind
    if re.fullmatch(r"[a-z0-9_.:-]{1,80}\.(ws|sse)\.connected", body):
        return "transport_connected"
    return None


_CHANNEL_EXTERNAL_PROVENANCE_META_KEYS = (
    "mcp_server",
    "mcp_method",
    "mcp_json",
    "sse_source",
    "sse_event",
    "sse_json",
    "stream_id",
    "sse_id",
    "cursor",
    "event_id",
    "message_id",
    "source_message_id",
    "rpc_id",
)


_CHANNEL_UNIQUE_REFERENCE_META_KEYS = (
    "message_id",
    "source_message_id",
    "assignment_id",
    "poll_id",
    "task_id",
    "job_id",
    "schedule_id",
    "reminder_id",
)


_CHANNEL_EVENT_ORDER_META_KEYS = (
    "stream_id",
    "cursor",
    "sse_id",
    "event_id",
    "sequence",
    "seq",
)


def _channel_message_meta_sources(message: dict[str, Any]) -> list[dict[str, Any]]:
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    sources: list[dict[str, Any]] = []
    if meta:
        sources.append(meta)
    for envelope_key in ("mcp_json", "sse_json"):
        envelope = meta.get(envelope_key)
        if not isinstance(envelope, dict):
            continue
        params = envelope.get("params")
        if isinstance(params, dict):
            nested_meta = params.get("meta")
            if isinstance(nested_meta, dict):
                sources.append(nested_meta)
        nested_meta = envelope.get("meta")
        if isinstance(nested_meta, dict):
            sources.append(nested_meta)
    return sources


def _channel_message_delivery_targets(message: dict[str, Any]) -> set[str]:
    return {item.strip().lower() for item in _as_string_list(message.get("delivery")) if item.strip()}


def _channel_message_is_web_chat_request(message: dict[str, Any]) -> bool:
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    source = str(meta.get("source") or "").strip().lower()
    kind = str(message.get("kind") or meta.get("kind") or "").strip().lower()
    return bool(
        source == "ciel-runtime-web-chat"
        or kind == "web_chat"
        or meta.get("reply_channel")
        or meta.get("reply_recipient")
    )


def _channel_message_has_external_provenance(message: dict[str, Any]) -> bool:
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    if _channel_message_is_web_chat_request(message):
        return True
    for key in _CHANNEL_EXTERNAL_PROVENANCE_META_KEYS:
        value = meta.get(key)
        if value is not None and str(value).strip():
            return True
    return False


def _channel_message_has_unique_reference(message: dict[str, Any]) -> bool:
    meta_sources = _channel_message_meta_sources(message)
    for key in _CHANNEL_UNIQUE_REFERENCE_META_KEYS:
        for meta in meta_sources:
            value = meta.get(key)
            if value is not None and str(value).strip():
                return True
    for meta in meta_sources:
        message_ids = meta.get("message_ids")
        if isinstance(message_ids, (list, tuple)) and any(str(item).strip() for item in message_ids):
            return True
        if isinstance(message_ids, str) and message_ids.strip():
            return True
        rooms = meta.get("rooms")
        if not isinstance(rooms, str) or not rooms.strip():
            continue
        try:
            parsed_rooms = json.loads(rooms)
        except Exception:
            continue
        if not isinstance(parsed_rooms, list):
            continue
        for room in parsed_rooms:
            if not isinstance(room, dict):
                continue
            room_message_ids = room.get("message_ids")
            if isinstance(room_message_ids, (list, tuple)) and any(str(item).strip() for item in room_message_ids):
                return True
    return False


def _channel_message_source_key(message: dict[str, Any]) -> str:
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    return str(meta.get("mcp_server") or meta.get("sse_source") or meta.get("source") or "").strip()


def _channel_message_kind_key(message: dict[str, Any]) -> str:
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    meta_kind = str(
        meta.get("kind")
        or meta.get("type")
        or meta.get("event_type")
        or meta.get("eventType")
        or meta.get("event")
        or ""
    ).strip()
    if meta_kind:
        return meta_kind
    return str(message.get("kind") or "").strip()


def _channel_message_topic_key(message: dict[str, Any]) -> str:
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    return str(
        meta.get("key")
        or meta.get("topic")
        or meta.get("resource")
        or meta.get("target")
        or ""
    ).strip()


def _channel_message_order_value(message: dict[str, Any]) -> tuple[int, int, int] | None:
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    for key in _CHANNEL_EVENT_ORDER_META_KEYS:
        raw = meta.get(key)
        if raw is None:
            continue
        text = str(raw).strip()
        if not text:
            continue
        match = re.fullmatch(r"(\d+)-(\d+)", text)
        if match:
            return (2, int(match.group(1)), int(match.group(2)))
        if text.isdigit():
            return (1, int(text), 0)
    if _channel_message_has_external_provenance(message):
        try:
            message_id = int(message.get("id") or 0)
        except Exception:
            message_id = 0
        if message_id > 0:
            return (3, message_id, 0)
    return None


def _channel_message_coalesce_key(message: dict[str, Any]) -> tuple[str, str, str, str, str] | None:
    if _channel_message_delivery_targets(message) and not _channel_message_has_external_provenance(message):
        return None
    if _channel_message_is_web_chat_request(message):
        return None
    if _channel_message_has_unique_reference(message):
        return None
    source = _channel_message_source_key(message)
    if not source:
        return None
    order = _channel_message_order_value(message)
    if order is None:
        return None
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    method = str(meta.get("mcp_method") or meta.get("sse_event") or "").strip()
    kind = _channel_message_kind_key(message)
    if not method and not kind:
        return None
    channel = str(message.get("channel") or meta.get("room_id") or meta.get("room") or meta.get("channel") or "").strip()
    topic = _channel_message_topic_key(message)
    return (source, channel, method, kind, topic)


def _channel_superseded_message_ids(messages: list[dict[str, Any]]) -> set[int]:
    latest: dict[tuple[str, str, str, str, str], tuple[tuple[int, int, int], int]] = {}
    superseded: set[int] = set()
    for message in messages:
        try:
            message_id = int(message.get("id") or 0)
        except Exception:
            continue
        if message_id <= 0:
            continue
        key = _channel_message_coalesce_key(message)
        if key is None:
            continue
        order = _channel_message_order_value(message)
        if order is None:
            continue
        previous = latest.get(key)
        if previous is None:
            latest[key] = (order, message_id)
            continue
        previous_order, previous_id = previous
        if (order, message_id) >= (previous_order, previous_id):
            superseded.add(previous_id)
            latest[key] = (order, message_id)
        else:
            superseded.add(message_id)
    return superseded


def _channel_pending_scan_limit() -> int:
    raw = os.environ.get("CIEL_RUNTIME_CHANNEL_PENDING_SCAN_LIMIT", "500")
    try:
        return max(100, min(5000, int(str(raw).strip())))
    except Exception:
        return 500


def _channel_stdin_wake_batch_limit() -> int:
    raw = os.environ.get("CIEL_RUNTIME_CHANNEL_WAKE_BATCH_LIMIT", "8")
    try:
        return max(1, min(50, int(str(raw).strip())))
    except Exception:
        return 8


def _channel_llm_message_skip_reason(message: dict[str, Any]) -> str | None:
    visibility = str(message.get("visibility") or "user").strip().lower()
    if visibility in {"hidden", "internal", "transport", "control", "system"}:
        return f"visibility_{visibility}"
    recipients = {item.strip().lower() for item in _as_string_list(message.get("recipients"))}
    if "internal" in recipients:
        return "recipient_internal"
    delivery = _as_string_list(message.get("delivery"))
    if delivery:
        normalized_delivery = {item.strip().lower() for item in delivery}
        if not ({"all", "*", "llm"} & normalized_delivery):
            return "delivery_not_llm"
    wake_reason = _channel_wake_message_noise_reason(message)
    if wake_reason:
        return wake_reason
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    sse_source = str(meta.get("sse_source") or meta.get("source") or "").strip().lower()
    sender = str(message.get("sender_id") or meta.get("sender_id") or "").strip().lower()
    if sse_source in _NATIVE_ROUTER_CHANNEL_NAMES or sender in _NATIVE_ROUTER_CHANNEL_NAMES:
        return "native_router_self_echo"
    meta_kind = str(meta.get("kind") or meta.get("type") or meta.get("event_type") or meta.get("eventType") or meta.get("event") or meta.get("status") or "").strip().lower()
    if meta_kind in _CHANNEL_CONTROL_KINDS:
        return meta_kind
    if not delivery and not _channel_message_has_external_provenance(message):
        return "unscoped_channel_message"
    return None


def _channel_wake_message_is_noise(message: dict[str, Any]) -> bool:
    return _channel_wake_message_noise_reason(message) is not None


def format_channel_wake_batch_prompt(messages: list[dict[str, Any]]) -> str:
    if len(messages) == 1:
        return format_channel_wake_prompt(messages[0])
    parts: list[str] = []
    for message in messages:
        channel = str(message.get("channel") or "default")
        sender = str(message.get("sender_id") or "channel")
        mid = str(message.get("id") or "")
        meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
        room = str(meta.get("room_id") or meta.get("room") or channel)
        thread = str(message.get("thread_id") or meta.get("thread_id") or "")
        body = str(message.get("message") or "")
        fields = [f"id={mid}", f"room={room}", f"from={sender}"]
        if thread:
            fields.append(f"thread={thread}")
        prompt_meta = _channel_prompt_metadata(message)
        if prompt_meta:
            fields.append(f"metadata={prompt_meta}")
        parts.append("(" + " ".join(fields) + ") " + json.dumps(body, ensure_ascii=False))
    return (
        f"[ciel-runtime external channel messages] {len(messages)} new messages: "
        + " ; ".join(parts)
    )


def _channel_message_llm_display_text(message: dict[str, Any]) -> str:
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    for key in ("mcp_json", "sse_json"):
        value = meta.get(key)
        if isinstance(value, (dict, list)):
            text = _pretty_json_value(value)
            header = _channel_message_source_header(message)
            return f"{header}\n\n{text}" if header else text
    return str(message.get("message") if message.get("message") is not None else "")


def _channel_source_header_scalar(value: Any) -> str:
    if value is None or isinstance(value, (dict, list)):
        return ""
    text = re.sub(r"\s+", " ", str(value)).strip()
    if not text or len(text) > 240:
        return ""
    return text


def _channel_first_source_header_value(message: dict[str, Any], keys: tuple[str, ...]) -> str:
    for source in _channel_message_meta_sources(message):
        for key in keys:
            if _metadata_key_is_sensitive(key):
                continue
            text = _channel_source_header_scalar(source.get(key))
            if text:
                return text
    return ""


def _channel_message_source_header(message: dict[str, Any]) -> str:
    meta = message.get("meta") if isinstance(message.get("meta"), dict) else {}
    if not any(isinstance(meta.get(key), (dict, list)) for key in ("mcp_json", "sse_json")):
        return ""
    room_name = _channel_first_source_header_value(message, ("room_name", "room_label", "title", "name"))
    room_id = _channel_first_source_header_value(message, ("room_id", "room"))
    channel = _channel_first_source_header_value(message, ("channel",)) or _channel_source_header_scalar(message.get("channel"))
    source = room_name or room_id or channel
    if not source:
        return ""
    if room_name and room_id and room_id != room_name:
        source_text = f"{room_name} (room_id={room_id})"
    else:
        source_text = source
    return f"[Source channel] {source_text}"


def format_channel_llm_delivery_wake_prompt(messages: list[dict[str, Any]]) -> str:
    return "\n\n".join(_channel_message_llm_display_text(message) for message in messages)


def format_channel_llm_batch_prompt(messages: list[dict[str, Any]]) -> str:
    return "\n\n".join(_channel_message_llm_display_text(message) for message in messages)


_CHANNEL_LLM_TOOL_CONTEXT_LOCK = threading.Lock()
_CHANNEL_LLM_TOOL_CONTEXT: dict[str, dict[str, Any]] = {}
_CHANNEL_LLM_TOOL_CONTEXT_LIMIT = 200
_CHANNEL_LLM_TOOL_CONTEXT_MAX_INJECT = 8
_CHANNEL_LLM_TOOL_CONTEXT_PROMPT_LIMIT = 4000


def _channel_injected_prompt_text(body: dict[str, Any]) -> str:
    metadata = body.get("metadata") if isinstance(body.get("metadata"), dict) else {}
    for message in reversed(body.get("messages") or []):
        if not isinstance(message, dict) or message.get("role") != "user":
            continue
        text = anthropic_content_to_text(message.get("content", ""))
        if metadata.get("ciel_runtime_channel_injected") and text:
            return truncate_for_prompt(text, _CHANNEL_LLM_TOOL_CONTEXT_PROMPT_LIMIT)
        if "[external channel input]" in text or "[ciel-runtime channel inbox]" in text:
            return truncate_for_prompt(text, _CHANNEL_LLM_TOOL_CONTEXT_PROMPT_LIMIT)
    return ""


def _remember_channel_injected_tool_use(source_body: dict[str, Any] | None, tool_use_id: str, tool_name: str, tool_input: Any) -> None:
    if not isinstance(source_body, dict) or not tool_use_id:
        return
    metadata = source_body.get("metadata") if isinstance(source_body.get("metadata"), dict) else {}
    if not metadata.get("ciel_runtime_channel_injected"):
        return
    context = {
        "created_at": time.time(),
        "channel_message_ids": str(metadata.get("ciel_runtime_channel_message_ids") or ""),
        "prompt": _channel_injected_prompt_text(source_body),
        "tool_name": tool_name,
        "tool_input": tool_input if isinstance(tool_input, (dict, list, str, int, float, bool)) or tool_input is None else str(tool_input),
    }
    with _CHANNEL_LLM_TOOL_CONTEXT_LOCK:
        _CHANNEL_LLM_TOOL_CONTEXT[tool_use_id] = context
        if len(_CHANNEL_LLM_TOOL_CONTEXT) > _CHANNEL_LLM_TOOL_CONTEXT_LIMIT:
            for old_id, _old in sorted(_CHANNEL_LLM_TOOL_CONTEXT.items(), key=lambda item: item[1].get("created_at", 0))[
                : len(_CHANNEL_LLM_TOOL_CONTEXT) - _CHANNEL_LLM_TOOL_CONTEXT_LIMIT
            ]:
                _CHANNEL_LLM_TOOL_CONTEXT.pop(old_id, None)
    router_log(
        "INFO",
        f"channel_llm_tool_context_stored tool_use_id={tool_use_id} tool={tool_name} message_ids={context['channel_message_ids']}",
    )


def remember_channel_injected_tool_uses(source_body: dict[str, Any] | None, message: dict[str, Any]) -> None:
    if not isinstance(message, dict):
        return
    for block in message.get("content") or []:
        if not isinstance(block, dict) or block.get("type") != "tool_use":
            continue
        _remember_channel_injected_tool_use(
            source_body,
            str(block.get("id") or ""),
            str(block.get("name") or "tool"),
            block.get("input"),
        )


def _take_channel_tool_result_contexts_for_body(body: dict[str, Any]) -> list[tuple[str, dict[str, Any]]]:
    found: list[tuple[str, dict[str, Any]]] = []
    with _CHANNEL_LLM_TOOL_CONTEXT_LOCK:
        for message in body.get("messages") or []:
            if not isinstance(message, dict) or message.get("role") != "user":
                continue
            for block in message.get("content") or []:
                if not isinstance(block, dict) or block.get("type") != "tool_result":
                    continue
                tool_use_id = str(block.get("tool_use_id") or "")
                context = _CHANNEL_LLM_TOOL_CONTEXT.pop(tool_use_id, None)
                if context:
                    found.append((tool_use_id, dict(context)))
                    if len(found) >= _CHANNEL_LLM_TOOL_CONTEXT_MAX_INJECT:
                        return found
    return found


def body_with_channel_tool_result_context(body: dict[str, Any]) -> dict[str, Any]:
    metadata = body.get("metadata") if isinstance(body.get("metadata"), dict) else {}
    if metadata.get("ciel_runtime_channel_tool_result_followup"):
        return body
    contexts = _take_channel_tool_result_contexts_for_body(body)
    if not contexts:
        return body
    parts = [
        "[ciel-runtime channel tool_result follow-up]",
        "tool_result data from a previous channel-injected tool call.",
    ]
    for tool_use_id, context in contexts:
        parts.append(
            "\n".join(
                [
                    f"tool_use_id={tool_use_id}",
                    f"tool={context.get('tool_name') or 'tool'}",
                    f"channel_message_ids={context.get('channel_message_ids') or ''}",
                    f"tool_input={json.dumps(context.get('tool_input'), ensure_ascii=False)}",
                    f"original_channel_prompt:\n{context.get('prompt') or '(not captured)'}",
                ]
            )
        )
    out = dict(body)
    messages = [m for m in body.get("messages", []) if isinstance(m, dict)]
    messages.append({"role": "user", "content": [{"type": "text", "text": "\n\n".join(parts)}]})
    out["messages"] = messages
    out_metadata = dict(metadata)
    out_metadata["ciel_runtime_channel_tool_result_followup"] = True
    out["metadata"] = out_metadata
    router_log(
        "INFO",
        "channel_llm_tool_result_context_injected tool_use_ids="
        + ",".join(tool_use_id for tool_use_id, _context in contexts),
    )
    return out


def _channel_llm_write_cursor_locked(last_id: int) -> None:
    CONFIG_DIR.mkdir(parents=True, exist_ok=True)
    tmp_path = CHANNEL_LLM_CURSOR_PATH.with_suffix(".json.tmp")
    tmp_path.write_text(json.dumps({"last_id": max(0, int(last_id))}, separators=(",", ":")) + "\n", encoding="utf-8")
    tmp_path.replace(CHANNEL_LLM_CURSOR_PATH)


def _channel_llm_read_cursor_locked() -> int:
    global _CHANNEL_LLM_CURSOR_LAST_ID
    if CHANNEL_LLM_CURSOR_PATH.exists():
        try:
            data = json.loads(CHANNEL_LLM_CURSOR_PATH.read_text(encoding="utf-8"))
            file_cursor = max(0, int(data.get("last_id") or 0))
            if _CHANNEL_LLM_CURSOR_LAST_ID is None or file_cursor > _CHANNEL_LLM_CURSOR_LAST_ID:
                _CHANNEL_LLM_CURSOR_LAST_ID = file_cursor
            return _CHANNEL_LLM_CURSOR_LAST_ID
        except Exception as exc:
            router_log("WARN", f"channel_llm_cursor_read_failed error={type(exc).__name__}: {exc}")
    if _CHANNEL_LLM_CURSOR_LAST_ID is not None:
        return _CHANNEL_LLM_CURSOR_LAST_ID
    _CHANNEL_LLM_CURSOR_LAST_ID = max(0, _chat_scan_max_id())
    try:
        _channel_llm_write_cursor_locked(_CHANNEL_LLM_CURSOR_LAST_ID)
    except Exception:
        pass
    return _CHANNEL_LLM_CURSOR_LAST_ID


def _channel_llm_clear_floor_read() -> int:
    try:
        if not CHANNEL_LLM_CLEAR_FLOOR_PATH.exists():
            return 0
        data = json.loads(CHANNEL_LLM_CLEAR_FLOOR_PATH.read_text(encoding="utf-8"))
        if not isinstance(data, dict):
            return 0
        return max(0, int(data.get("last_id") or 0))
    except Exception as exc:
        router_log("WARN", f"channel_llm_clear_floor_read_failed error={type(exc).__name__}: {exc}")
        return 0


def _channel_llm_clear_floor_write(last_id: int) -> None:
    CHANNEL_LLM_CLEAR_FLOOR_PATH.parent.mkdir(parents=True, exist_ok=True)
    payload = {"last_id": max(0, int(last_id)), "updated_at": time.time()}
    tmp_path = CHANNEL_LLM_CLEAR_FLOOR_PATH.with_suffix(".json.tmp")
    tmp_path.write_text(json.dumps(payload, separators=(",", ":")) + "\n", encoding="utf-8")
    tmp_path.replace(CHANNEL_LLM_CLEAR_FLOOR_PATH)


def _channel_llm_clamp_to_clear_floor(recovered: int) -> int:
    clear_floor = _channel_llm_clear_floor_read()
    if clear_floor > 0 and recovered < clear_floor:
        router_log(
            "INFO",
            f"channel_stdin_proxy_recovery_clamped recovered_cursor={recovered} clear_floor={clear_floor}",
        )
        return clear_floor
    return recovered


def reset_channel_llm_delivery_cursor(last_id: int | None = None) -> int:
    global _CHANNEL_LLM_CURSOR_LAST_ID
    with _CHANNEL_LLM_CURSOR_LOCK:
        _CHANNEL_LLM_CURSOR_LAST_ID = max(0, int(last_id if last_id is not None else _chat_scan_max_id()))
        try:
            _channel_llm_write_cursor_locked(_CHANNEL_LLM_CURSOR_LAST_ID)
        except Exception as exc:
            router_log("WARN", f"channel_llm_cursor_write_failed error={type(exc).__name__}: {exc}")
        return _CHANNEL_LLM_CURSOR_LAST_ID


def ensure_channel_llm_delivery_cursor_initialized() -> int:
    with _CHANNEL_LLM_CURSOR_LOCK:
        return _channel_llm_read_cursor_locked()


def prepare_channel_llm_delivery_for_launch() -> int:
    # chat-messages.jsonl is a transient bridge queue, not the durable MCP inbox.
    # On a new Claude Code process, replaying old rows left by a previous process
    # surfaces stale "one more" channel messages at startup. Do not fast-forward
    # over very recent rows, though: users often restart immediately after an
    # injected event, and those fresh rows still need to be delivered.
    current = ensure_channel_llm_delivery_cursor_initialized()
    recent_seconds = _channel_launch_recent_seconds()
    if recent_seconds <= 0:
        target = _chat_scan_max_id()
    else:
        target = _chat_scan_max_id_before_epoch(time.time() - recent_seconds)
    last_id = reset_channel_llm_delivery_cursor(max(current, target))
    _write_channel_llm_launch_guard(last_id)
    router_log(
        "INFO",
        "channel_llm_cursor_fast_forward_on_launch "
        f"last_id={last_id} previous_cursor={current} recent_seconds={recent_seconds:g}",
    )
    return last_id


def clear_channel_backlog() -> dict[str, Any]:
    global _CHANNEL_LLM_CURSOR_LAST_ID, _CHANNEL_MCP_CURSOR_LAST_ID
    chat_tail = max(0, _chat_scan_max_id())

    with _CHANNEL_LLM_CURSOR_LOCK:
        old_llm = _channel_llm_read_cursor_locked()
        _CHANNEL_LLM_CURSOR_LAST_ID = chat_tail
        try:
            _channel_llm_write_cursor_locked(chat_tail)
        except Exception as exc:
            router_log("WARN", f"channel_llm_cursor_write_failed error={type(exc).__name__}: {exc}")
        try:
            _channel_llm_clear_floor_write(chat_tail)
        except Exception as exc:
            router_log("WARN", f"channel_llm_clear_floor_write_failed error={type(exc).__name__}: {exc}")
    _CHANNEL_STDIN_RECOVERY_CACHE.clear()

    with _CHANNEL_MCP_CURSOR_LOCK:
        old_mcp = _channel_mcp_read_cursor_locked()
        _CHANNEL_MCP_CURSOR_LAST_ID = chat_tail
        try:
            _channel_mcp_write_cursor_locked(chat_tail)
        except Exception as exc:
            router_log("WARN", f"channel_mcp_cursor_write_failed error={type(exc).__name__}: {exc}")

    with _CHANNEL_MCP_LOCK:
        for state in _CHANNEL_MCP_SESSIONS.values():
            try:
                state["last_id"] = max(int(state.get("last_id") or 0), chat_tail)
            except Exception:
                state["last_id"] = chat_tail

    with _CHAT_CONDITION:
        _CHAT_CONDITION.notify_all()
    stats = {
        "chat_tail": chat_tail,
        "discarded_llm": max(0, chat_tail - int(old_llm or 0)),
        "discarded_mcp": max(0, chat_tail - int(old_mcp or 0)),
        "mcp_sessions_updated": len(_CHANNEL_MCP_SESSIONS),
    }
    router_log(
        "INFO",
        "channel_backlog_cleared "
        f"chat_tail={chat_tail} "
        f"discarded_llm={stats['discarded_llm']} discarded_mcp={stats['discarded_mcp']} "
        f"mcp_sessions_updated={stats['mcp_sessions_updated']}",
    )
    return stats


def channel_backlog_status() -> dict[str, Any]:
    chat_tail = max(0, _chat_scan_max_id())
    with _CHANNEL_LLM_CURSOR_LOCK:
        llm_cursor = _channel_llm_read_cursor_locked()
    with _CHANNEL_MCP_CURSOR_LOCK:
        mcp_cursor = _channel_mcp_read_cursor_locked()
    return {
        "chat_tail": chat_tail,
        "pending_llm": max(0, chat_tail - int(llm_cursor or 0)),
        "pending_mcp": max(0, chat_tail - int(mcp_cursor or 0)),
        "mcp_sessions": len(_CHANNEL_MCP_SESSIONS),
    }


def _metadata_int(metadata: dict[str, Any], key: str) -> int | None:
    try:
        value = metadata.get(key)
        if value is None or value == "":
            return None
        return max(0, int(value))
    except Exception:
        return None


def _commit_channel_llm_cursor_if_newer(last_id: int | None) -> None:
    global _CHANNEL_LLM_CURSOR_LAST_ID
    if last_id is None:
        return
    with _CHANNEL_LLM_CURSOR_LOCK:
        current = _channel_llm_read_cursor_locked()
        if last_id <= current:
            return
        _CHANNEL_LLM_CURSOR_LAST_ID = last_id
        try:
            _channel_llm_write_cursor_locked(last_id)
        except Exception as exc:
            router_log("WARN", f"channel_llm_cursor_write_failed error={type(exc).__name__}: {exc}")


CIEL_RUNTIME_INTERNAL_METADATA_PREFIX = "ciel_runtime_"


def body_without_ciel_runtime_internal_metadata(body: dict[str, Any]) -> dict[str, Any]:
    """Return an upstream-safe copy with ciel-runtime private metadata removed."""
    metadata = body.get("metadata") if isinstance(body.get("metadata"), dict) else None
    if not metadata:
        return body
    internal_keys = [
        key
        for key in metadata
        if str(key).startswith(CIEL_RUNTIME_INTERNAL_METADATA_PREFIX)
    ]
    if not internal_keys:
        return body
    public_metadata = {
        key: value
        for key, value in metadata.items()
        if not str(key).startswith(CIEL_RUNTIME_INTERNAL_METADATA_PREFIX)
    }
    out = dict(body)
    if public_metadata:
        out["metadata"] = public_metadata
    else:
        out.pop("metadata", None)
    return out


def commit_pending_channel_delivery_cursors(
    body: dict[str, Any],
    handler: BaseHTTPRequestHandler | None = None,
    metadata: dict[str, Any] | None = None,
) -> None:
    if not isinstance(metadata, dict):
        metadata = body.get("metadata") if isinstance(body.get("metadata"), dict) else {}
    if not metadata:
        return
    if handler is not None:
        status = _handler_response_status(handler)
        if status is None or status < 200 or status >= 400:
            router_log(
                "INFO",
                f"channel_delivery_cursor_deferred status={status if status is not None else '-'}",
            )
            return
        if _channel_delivery_metadata(metadata) and not pending_channel_delivery_confirmed(handler):
            reason = str(getattr(handler, "_ciel_runtime_channel_delivery_reason", "unconfirmed") or "unconfirmed")
            router_log("INFO", f"channel_delivery_cursor_deferred reason={reason}")
            return
    message_cursor = _metadata_int(metadata, "ciel_runtime_channel_cursor_last_id")
    _commit_channel_llm_cursor_if_newer(message_cursor)


_CHANNEL_WAKE_PROMPT_IDS_RE = re.compile(r"\b(?:id|ids|pending_ids|message_ids)\s*=\s*([0-9][0-9,\s]*)")


def _channel_prompt_match_text(text: str) -> str:
    return re.sub(r"\s+", " ", str(text or "")).strip()


def _channel_prompt_contains(candidate: str, prompt: str) -> bool:
    needle = _channel_prompt_match_text(prompt)
    if not needle:
        return False
    haystack = _channel_prompt_match_text(candidate)
    return bool(haystack and needle in haystack)


def _channel_prompt_message_ids(text: str) -> set[int]:
    ids: set[int] = set()
    for match in _CHANNEL_WAKE_PROMPT_IDS_RE.finditer(str(text or "")):
        for raw in re.split(r"\D+", match.group(1)):
            if not raw:
                continue
            try:
                message_id = int(raw)
            except Exception:
                continue
            if message_id > 0:
                ids.add(message_id)
    return ids


def _channel_stdin_wake_claim_ttl_seconds() -> float:
    raw = os.environ.get("CIEL_RUNTIME_CHANNEL_WAKE_CLAIM_TTL_SECONDS")
    if raw is None:
        return 300.0
    try:
        return max(5.0, min(1800.0, float(raw)))
    except Exception:
        return 300.0


def _channel_stdin_wake_claims_read_locked(now: float | None = None) -> dict[str, Any]:
    current = time.time() if now is None else float(now)
    ttl = _channel_stdin_wake_claim_ttl_seconds()
    try:
        data = json.loads(CHANNEL_STDIN_WAKE_CLAIMS_PATH.read_text(encoding="utf-8"))
        claims = data.get("claims") if isinstance(data, dict) else {}
        if not isinstance(claims, dict):
            return {}
        out: dict[str, Any] = {}
        for key, value in claims.items():
            if not isinstance(value, dict):
                continue
            try:
                claimed_at = float(value.get("claimed_at") or 0)
            except Exception:
                claimed_at = 0.0
            if claimed_at > 0 and current - claimed_at > ttl:
                continue
            out[str(key)] = dict(value)
        return out
    except FileNotFoundError:
        return {}
    except Exception as exc:
        router_log("WARN", f"channel_stdin_wake_claims_read_failed error={type(exc).__name__}: {exc}")
        return {}


def _channel_stdin_wake_claims_write_locked(claims: dict[str, Any]) -> None:
    CONFIG_DIR.mkdir(parents=True, exist_ok=True)
    tmp_path = CHANNEL_STDIN_WAKE_CLAIMS_PATH.with_suffix(".json.tmp")
    tmp_path.write_text(json.dumps({"claims": claims}, ensure_ascii=False, separators=(",", ":")) + "\n", encoding="utf-8")
    tmp_path.replace(CHANNEL_STDIN_WAKE_CLAIMS_PATH)


def _channel_stdin_wake_claim_prompt(message_id: int) -> str:
    if message_id <= 0:
        return ""
    with _CHANNEL_STDIN_WAKE_LOCK:
        prompt = _CHANNEL_STDIN_WAKE_PROMPTS.get(message_id)
    if prompt:
        return prompt
    with _chat_messages_file_lock():
        claim = _channel_stdin_wake_claims_read_locked().get(str(message_id))
    if not isinstance(claim, dict):
        return ""
    prompt = claim.get("prompt")
    return str(prompt) if isinstance(prompt, str) else ""


def _channel_stdin_claim_wake_prompt(message_id: int, prompt: str) -> bool:
    if message_id <= 0:
        return True
    normalized_prompt = _channel_prompt_match_text(prompt)
    if not normalized_prompt:
        return True
    with _chat_messages_file_lock():
        claims = _channel_stdin_wake_claims_read_locked()
        existing = claims.get(str(message_id))
        if isinstance(existing, dict):
            return False
        claims[str(message_id)] = {"claimed_at": time.time(), "prompt": prompt}
        _channel_stdin_wake_claims_write_locked(claims)
    return True


def _channel_stdin_clear_wake_claim(message_id: int) -> None:
    if message_id <= 0:
        return
    with _chat_messages_file_lock():
        claims = _channel_stdin_wake_claims_read_locked()
        if str(message_id) not in claims:
            return
        claims.pop(str(message_id), None)
        _channel_stdin_wake_claims_write_locked(claims)


def _channel_prompt_references_message_id(text: str, message_id: int, prompt_texts: list[str] | tuple[str, ...] | None = None) -> bool:
    if message_id in _channel_prompt_message_ids(text):
        return True
    prompts: list[str] = []
    if prompt_texts:
        prompts.extend(str(item) for item in prompt_texts if str(item or "").strip())
    if prompt_texts is None:
        claimed_prompt = _channel_stdin_wake_claim_prompt(message_id)
        if claimed_prompt:
            prompts.append(claimed_prompt)
    for prompt in prompts:
        if _channel_prompt_contains(str(text or ""), prompt):
            return True
    return False


def _channel_message_ids_already_in_request(body: dict[str, Any]) -> set[int]:
    ids: set[int] = set()
    for message in body.get("messages") or []:
        if not isinstance(message, dict):
            continue
        text = anthropic_content_to_text(message.get("content"))
        if "ciel-runtime external channel message" not in text and "[external channel input]" not in text:
            continue
        ids.update(_channel_prompt_message_ids(text))
    return ids


def body_with_pending_channel_messages(body: dict[str, Any]) -> dict[str, Any]:
    global _CHANNEL_LLM_CURSOR_LAST_ID
    wake_request = channel_llm_wake_request(body)
    if plan_mode_active(body):
        if not wake_request:
            router_log("INFO", "channel_llm_inject_skipped reason=plan_mode_active")
            return body
        router_log("INFO", "channel_llm_inject_plan_mode_override reason=channel_wake")
    cfg = load_config()
    if channel_delivery_mode(cfg) != "llm":
        return body
    ids_already_in_request = _channel_message_ids_already_in_request(body)
    with _CHANNEL_LLM_CURSOR_LOCK:
        last_id = _channel_llm_read_cursor_locked()
        pending: list[dict[str, Any]] = []
        max_seen = last_id
        candidates = read_chat_messages(last_id, None, None, _channel_pending_scan_limit())
        superseded_ids = _channel_superseded_message_ids(candidates)
        for message in candidates:
            try:
                message_id = int(message.get("id") or 0)
            except Exception:
                continue
            if message_id in ids_already_in_request:
                max_seen = max(max_seen, message_id)
                router_log(
                    "INFO",
                    f"channel_llm_inject_skipped message_id={message.get('id')} channel={message.get('channel')} reason=already_in_request",
                )
                continue
            if message_id in superseded_ids:
                max_seen = max(max_seen, message_id)
                router_log(
                    "INFO",
                    f"channel_llm_inject_skipped message_id={message.get('id')} channel={message.get('channel')} reason=superseded_channel_notice",
                )
                continue
            skip_reason = _channel_llm_message_skip_reason(message)
            if skip_reason:
                max_seen = max(max_seen, message_id)
                router_log(
                    "INFO",
                    f"channel_llm_inject_skipped message_id={message.get('id')} channel={message.get('channel')} reason={skip_reason}",
                )
                continue
            with _CHANNEL_STDIN_WAKE_LOCK:
                stdin_wake_delivered = message_id in _CHANNEL_STDIN_WAKE_DELIVERED
            stdin_wake_claimed = bool(_channel_stdin_wake_claim_prompt(message_id))
            if stdin_wake_delivered or stdin_wake_claimed:
                reason = "stdin_wake_delivered" if stdin_wake_delivered else "stdin_wake_claimed"
                router_log(
                    "INFO",
                    f"channel_llm_inject_skipped message_id={message.get('id')} channel={message.get('channel')} reason={reason}",
                )
                continue
            pending.append(message)
            max_seen = message_id
            break
        if not pending:
            if max_seen != last_id:
                _CHANNEL_LLM_CURSOR_LAST_ID = max_seen
                try:
                    _channel_llm_write_cursor_locked(max_seen)
                except Exception as exc:
                    router_log("WARN", f"channel_llm_cursor_write_failed error={type(exc).__name__}: {exc}")
            return body_without_channel_llm_wake_prompt(body) if wake_request else body
    base_body = body_without_channel_llm_wake_prompt(body) if wake_request else body
    messages = [m for m in base_body.get("messages", []) if isinstance(m, dict)]
    messages.append({"role": "user", "content": [{"type": "text", "text": format_channel_llm_batch_prompt(pending)}]})
    out = dict(base_body)
    out["messages"] = messages
    ids = ",".join(str(message.get("id") or "") for message in pending)
    channels = ",".join(sorted({str(message.get("channel") or "default") for message in pending}))
    out_metadata = dict(out.get("metadata") if isinstance(out.get("metadata"), dict) else {})
    out_metadata["ciel_runtime_channel_injected"] = True
    out_metadata["ciel_runtime_channel_message_ids"] = ids
    out_metadata["ciel_runtime_channel_cursor_last_id"] = str(max_seen)
    out["metadata"] = out_metadata
    router_log("INFO", f"channel_llm_injected count={len(pending)} message_ids={ids} channels={channels}")
    return out


def _write_fd_all(fd: int, data: bytes) -> None:
    writer = getattr(fd, "write", None)
    if callable(writer):
        writer(data)
        return
    view = memoryview(data)
    while view:
        written = os.write(fd, view)
        view = view[written:]


def _channel_platform_default_enter_bytes(platform: str | None = None, os_name: str | None = None) -> bytes:
    sys_platform = str(platform if platform is not None else sys.platform).lower()
    os_family = str(os_name if os_name is not None else os.name).lower()
    if os_family == "nt" or sys_platform.startswith(("win", "cygwin", "msys")):
        return b"\r\n"
    if os_family == "posix":
        return b"\r\n"
    return b"\r\n"


def _channel_wake_enter_bytes(value: str | bytes | None = None) -> bytes:
    raw: str | bytes | None = value
    if raw is None:
        raw = os.environ.get("CIEL_RUNTIME_CHANNEL_WAKE_ENTER")
        if raw is None:
            return _channel_platform_default_enter_bytes()
    if isinstance(raw, bytes):
        return raw if raw in (b"\n", b"\r", b"\r\n") else _channel_platform_default_enter_bytes()
    normalized = str(raw or "").strip().lower()
    if normalized in {"", "auto", "default", "platform"}:
        return _channel_platform_default_enter_bytes()
    if normalized in {"lf", "nl", "newline", "linefeed", "\\n"}:
        return b"\n"
    if normalized in {"cr", "return", "carriage-return", "carriage_return", "\\r"}:
        return b"\r"
    if normalized in {"crlf", "cr-lf", "return-newline", "\\r\\n"}:
        return b"\r\n"
    return _channel_platform_default_enter_bytes()


def _channel_wake_enter_env_is_fixed() -> bool:
    raw = os.environ.get("CIEL_RUNTIME_CHANNEL_WAKE_ENTER")
    if raw is None:
        return False
    return str(raw).strip().lower() not in {"", "auto", "default", "platform"}


def _channel_enter_bytes_from_user_input(data: bytes) -> bytes | None:
    if not data:
        return None
    if data in (b"\n", b"\r", b"\r\n"):
        return data
    last_lf = data.rfind(b"\n")
    last_cr = data.rfind(b"\r")
    if last_lf < 0 and last_cr < 0:
        return None
    if last_lf > last_cr:
        return b"\r\n" if last_lf > 0 and data[last_lf - 1 : last_lf] == b"\r" else b"\n"
    return b"\r\n" if last_cr + 1 < len(data) and data[last_cr + 1 : last_cr + 2] == b"\n" else b"\r"


def _channel_synthetic_enter_bytes_from_user_input(data: bytes, *, normalize_bare_cr: bool = True) -> bytes | None:
    observed = _channel_enter_bytes_from_user_input(data)
    if observed == b"\r" and normalize_bare_cr:
        # Bare CR is common from raw POSIX terminals, but synthetic CR-only
        # writes can sit in Claude Code's line editor on some PTY stacks.
        return b"\r\n"
    return observed


def _channel_enter_label(enter_bytes: bytes) -> str:
    if enter_bytes == b"\r":
        return "cr"
    if enter_bytes == b"\r\n":
        return "crlf"
    return "lf"


def _channel_wake_input_bytes(prompt: str, enter_bytes: bytes | None = None) -> bytes:
    # Ctrl-U clears any stale line editor text before submitting the synthetic prompt.
    # Claude Code's interactive input is terminal-driven; the submit byte can
    # differ by PTY/input stack, so callers pass the observed Enter sequence.
    return b"\x15" + prompt.encode("utf-8", errors="replace") + _channel_wake_enter_bytes(enter_bytes)


def _channel_wake_submit_delay_seconds() -> float:
    raw = os.environ.get("CIEL_RUNTIME_CHANNEL_WAKE_SUBMIT_DELAY_MS")
    if raw is None:
        return 0.08
    try:
        return max(0.0, min(2.0, float(raw) / 1000.0))
    except Exception:
        return 0.08


def _bounded_delay_seconds(raw: Any, default_seconds: float, *, minimum: float, maximum: float) -> float:
    try:
        return max(minimum, min(maximum, float(raw) / 1000.0))
    except Exception:
        return default_seconds


def _channel_current_tmux_pane_text() -> str | None:
    pane = str(os.environ.get("TMUX_PANE") or "").strip()
    if not pane or not find_executable("tmux"):
        return None
    try:
        result = subprocess.run(
            ["tmux", "capture-pane", "-pt", pane, "-S", "-200"],
            stdout=subprocess.PIPE,
            stderr=subprocess.DEVNULL,
            text=True,
            timeout=1.0,
            check=False,
        )
    except Exception:
        return None
    if result.returncode != 0:
        return None
    return result.stdout or ""


def _channel_wake_submit_retry_delay_seconds() -> float:
    raw = os.environ.get("CIEL_RUNTIME_CHANNEL_WAKE_SUBMIT_RETRY_DELAY_MS")
    if raw is None:
        return 0.9
    try:
        return max(0.05, min(5.0, float(raw) / 1000.0))
    except Exception:
        return 0.9


def _codex_channel_wake_submit_retries() -> int:
    raw = os.environ.get("CIEL_RUNTIME_CODEX_CHANNEL_WAKE_SUBMIT_RETRIES")
    if raw is None:
        return 4
    try:
        return max(1, min(8, int(str(raw).strip())))
    except Exception:
        return 4


def _codex_channel_wake_submit_delay_seconds() -> float:
    raw = os.environ.get("CIEL_RUNTIME_CODEX_CHANNEL_WAKE_SUBMIT_DELAY_MS")
    if raw is None:
        return 0.25
    return _bounded_delay_seconds(raw, 0.25, minimum=0.13, maximum=5.0)


def _windows_channel_startup_grace_seconds() -> float:
    """Allow an interactive Windows TUI to begin reading console input."""
    raw = os.environ.get("CIEL_RUNTIME_WINDOWS_CHANNEL_STARTUP_GRACE_MS")
    if raw is None:
        return 8.0
    return _bounded_delay_seconds(raw, 8.0, minimum=0.0, maximum=60.0)


def _write_channel_wake_prompt(
    master_fd: int,
    prompt: str,
    enter_bytes: bytes | None = None,
    *,
    submit_retry_count: int = 1,
    confirm_submit: bool = False,
    bracketed_paste: bool = False,
    submit_delay_seconds: float | None = None,
) -> None:
    delay = _channel_wake_submit_delay_seconds() if submit_delay_seconds is None else max(0.0, float(submit_delay_seconds))
    submit_bytes = _channel_wake_enter_bytes(enter_bytes)
    retry_count = max(1, min(8, int(submit_retry_count or 1)))
    injector = ChannelPromptInjector(
        sleep=time.sleep,
        retry_delay_seconds=_channel_wake_submit_retry_delay_seconds,
        snapshot=_channel_current_tmux_pane_text,
        log=router_log,
    )
    injector.inject(
        CallableInputTransport(master_fd, _write_fd_all),
        PromptInjection(
            prompt=prompt,
            policy=RuntimeInjectionPolicy(
                runtime="interactive-cli",
                clear_input=b"\x15",
                submit_input=submit_bytes,
                submit_delay_seconds=delay,
                submit_attempts=retry_count,
                confirm_submission=confirm_submit,
                bracketed_paste=bracketed_paste,
            ),
        ),
    )


_CHANNEL_TRANSCRIPT_CACHE: dict[str, Any] = {"checked_at": 0.0, "path": None}
_CHANNEL_TRANSCRIPT_SCOPE: dict[str, Any] = {
    "runtime": "",
    "started_at": 0.0,
    "codex_home": None,
}
_CHANNEL_STDIN_RECOVERY_CACHE: dict[str, Any] = {
    "checked_at": 0.0,
    "last_id": None,
    "marker": None,
    "recovered_last_id": None,
}


def _set_channel_transcript_scope(runtime: str, *, started_at: float | None = None, codex_home: Path | None = None) -> None:
    _CHANNEL_TRANSCRIPT_SCOPE["runtime"] = str(runtime or "").strip().lower()
    _CHANNEL_TRANSCRIPT_SCOPE["started_at"] = time.time() if started_at is None else float(started_at)
    _CHANNEL_TRANSCRIPT_SCOPE["codex_home"] = Path(codex_home).expanduser() if codex_home is not None else None
    _CHANNEL_TRANSCRIPT_CACHE.clear()
    _CHANNEL_TRANSCRIPT_CACHE.update({"checked_at": 0.0, "path": None})


def _channel_transcript_roots() -> tuple[tuple[Path, str], ...]:
    runtime = str(_CHANNEL_TRANSCRIPT_SCOPE.get("runtime") or "").strip().lower()
    claude_root = (HOME / ".claude" / "projects", "*/*.jsonl")
    configured_codex_home = _CHANNEL_TRANSCRIPT_SCOPE.get("codex_home")
    codex_home = Path(configured_codex_home) if isinstance(configured_codex_home, Path) else HOME / ".codex"
    codex_root = (codex_home / "sessions", "**/*.jsonl")
    if runtime == "codex":
        return (codex_root,)
    if runtime == "claude":
        return (claude_root,)
    return (claude_root, codex_root)


def _latest_claude_transcript_path(ttl_seconds: float = 2.0) -> Path | None:
    now = time.time()
    cached_at = float(_CHANNEL_TRANSCRIPT_CACHE.get("checked_at") or 0.0)
    cached_path = _CHANNEL_TRANSCRIPT_CACHE.get("path")
    if now - cached_at < ttl_seconds:
        return cached_path if isinstance(cached_path, Path) else None
    latest: Path | None = None
    latest_mtime = -1.0
    transcript_roots = _channel_transcript_roots()
    scope_started_at = float(_CHANNEL_TRANSCRIPT_SCOPE.get("started_at") or 0.0)
    for root, pattern in transcript_roots:
        try:
            paths = root.glob(pattern)
        except Exception:
            continue
        for path in paths:
            try:
                mtime = path.stat().st_mtime
            except OSError:
                continue
            # A previous interrupted run can end with task_started and no matching
            # completion event. It must not make a newly launched idle client look
            # permanently busy and suppress external input injection.
            if scope_started_at > 0 and mtime < scope_started_at - 1.0:
                continue
            if mtime > latest_mtime:
                latest = path
                latest_mtime = mtime
    _CHANNEL_TRANSCRIPT_CACHE["checked_at"] = now
    _CHANNEL_TRANSCRIPT_CACHE["path"] = latest
    return latest


def _read_file_tail_text(path: Path, max_bytes: int = 512 * 1024) -> str:
    try:
        size = path.stat().st_size
        with path.open("rb") as f:
            if size > max_bytes:
                f.seek(max(0, size - max_bytes))
            return f.read(max_bytes).decode("utf-8", errors="replace")
    except Exception:
        return ""


def _channel_stdin_wake_state(message_id: int) -> str:
    if message_id <= 0:
        return "completed"
    path = _latest_claude_transcript_path()
    if path is None:
        return "unknown"
    text = _read_file_tail_text(path)
    if not text:
        return "unknown"
    return _channel_stdin_wake_state_from_text(message_id, text)


def _channel_stdin_wake_state_for_message(message: dict[str, Any], prompt: str | None = None) -> str:
    try:
        message_id = int(message.get("id") or 0)
    except Exception:
        message_id = 0
    if message_id <= 0:
        return "completed"
    path = _latest_claude_transcript_path()
    if path is None:
        return "unknown"
    text = _read_file_tail_text(path)
    if not text:
        return "unknown"
    prompt_candidates: list[str] = []
    if prompt:
        prompt_candidates.append(prompt)
    body = str(message.get("message") if message.get("message") is not None else "")
    if body:
        prompt_candidates.append(body)
    return _channel_stdin_wake_state_from_text(message_id, text, prompt_candidates)


def _channel_transcript_record_timestamp_seconds(record: dict[str, Any]) -> float | None:
    raw = record.get("timestamp")
    if raw is None and isinstance(record.get("attachment"), dict):
        raw = record["attachment"].get("timestamp")
    if raw is None:
        return None
    if isinstance(raw, (int, float)):
        return float(raw)
    text = str(raw or "").strip()
    if not text:
        return None
    try:
        return datetime.fromisoformat(text.replace("Z", "+00:00")).timestamp()
    except Exception:
        return None


def _channel_transcript_content_text(value: Any) -> str:
    if isinstance(value, str):
        return value
    if isinstance(value, dict):
        parts: list[str] = []
        for key in ("text", "content", "input_text", "output_text", "message"):
            raw = value.get(key)
            if isinstance(raw, str):
                parts.append(raw)
            elif isinstance(raw, (dict, list)):
                nested = _channel_transcript_content_text(raw)
                if nested:
                    parts.append(nested)
        return "\n".join(parts)
    if isinstance(value, list):
        parts = []
        for item in value:
            nested = _channel_transcript_content_text(item)
            if nested:
                parts.append(nested)
        return "\n".join(parts)
    return ""


def _channel_transcript_user_text(record: dict[str, Any]) -> str:
    record_type = str(record.get("type") or "")
    message = record.get("message")
    message_obj = message if isinstance(message, dict) else {}
    if record_type == "user" or str(message_obj.get("role") or "") == "user":
        return _channel_transcript_content_text(message_obj.get("content"))
    payload = record.get("payload")
    payload_obj = payload if isinstance(payload, dict) else {}
    payload_type = str(payload_obj.get("type") or "")
    payload_role = str(payload_obj.get("role") or "")
    if record_type == "response_item" and payload_type == "message" and payload_role == "user":
        return _channel_transcript_content_text(payload_obj.get("content"))
    if record_type == "event_msg" and payload_type == "user_message":
        return _channel_transcript_content_text(payload_obj.get("message"))
    return ""


def _channel_transcript_is_assistant_message(record: dict[str, Any]) -> bool:
    record_type = str(record.get("type") or "")
    message = record.get("message")
    message_obj = message if isinstance(message, dict) else {}
    message_role = str(message_obj.get("role") or "")
    if record_type == "assistant" or message_role == "assistant" or str(record.get("subtype") or "") == "turn_duration":
        return True
    payload = record.get("payload")
    payload_obj = payload if isinstance(payload, dict) else {}
    return (
        record_type == "response_item"
        and str(payload_obj.get("type") or "") == "message"
        and str(payload_obj.get("role") or "") == "assistant"
    )


def _channel_transcript_tool_call_id(value: dict[str, Any]) -> str:
    for key in ("call_id", "id", "tool_call_id"):
        raw = value.get(key)
        if isinstance(raw, str) and raw.strip():
            return raw.strip()
    return ""


def _channel_stdin_wake_queued_age_seconds_from_text(
    message_id: int,
    text: str,
    prompt_texts: list[str] | tuple[str, ...] | None = None,
    *,
    now: float | None = None,
) -> float | None:
    if message_id <= 0:
        return None
    prompt_candidates: list[str] = []
    if prompt_texts:
        prompt_candidates.extend(str(item) for item in prompt_texts if str(item or "").strip())
    claimed_prompt = _channel_stdin_wake_claim_prompt(message_id)
    if claimed_prompt:
        prompt_candidates.append(claimed_prompt)
    latest_queued_at: float | None = None

    for raw_line in text.splitlines():
        try:
            record = json.loads(raw_line)
        except Exception:
            continue
        if not isinstance(record, dict):
            continue
        record_type = str(record.get("type") or "")
        candidate = ""
        if record_type == "queue-operation" and record.get("operation") == "enqueue":
            raw = record.get("content")
            if isinstance(raw, str):
                candidate = raw
        elif record_type == "attachment":
            attachment = record.get("attachment")
            if isinstance(attachment, dict) and attachment.get("type") == "queued_command":
                raw = attachment.get("prompt")
                if isinstance(raw, str):
                    candidate = raw
        user_text = _channel_transcript_user_text(record)
        if user_text and _channel_prompt_references_message_id(user_text, message_id, prompt_candidates):
            return None
        if not candidate or not _channel_prompt_references_message_id(candidate, message_id, prompt_candidates):
            continue
        timestamp = _channel_transcript_record_timestamp_seconds(record)
        if timestamp is not None:
            latest_queued_at = max(latest_queued_at or 0.0, timestamp)
    if latest_queued_at is None:
        return None
    return max(0.0, (time.time() if now is None else float(now)) - latest_queued_at)


def _channel_stdin_wake_queued_is_stale_for_message(message: dict[str, Any], prompt: str | None = None) -> bool:
    try:
        message_id = int(message.get("id") or 0)
    except Exception:
        message_id = 0
    if message_id <= 0:
        return False
    path = _latest_claude_transcript_path()
    if path is None:
        return False
    text = _read_file_tail_text(path)
    if not text:
        return False
    prompt_candidates: list[str] = []
    if prompt:
        prompt_candidates.append(prompt)
    body = str(message.get("message") if message.get("message") is not None else "")
    if body:
        prompt_candidates.append(body)
    age = _channel_stdin_wake_queued_age_seconds_from_text(message_id, text, prompt_candidates)
    return age is not None and age >= _channel_stdin_inflight_stale_seconds()


def _channel_stdin_wake_state_from_text(
    message_id: int,
    text: str,
    prompt_texts: list[str] | tuple[str, ...] | None = None,
) -> str:
    if message_id <= 0:
        return "completed"
    prompt_candidates: list[str] = []
    if prompt_texts:
        prompt_candidates.extend(str(item) for item in prompt_texts if str(item or "").strip())
    claimed_prompt = _channel_stdin_wake_claim_prompt(message_id)
    if claimed_prompt:
        prompt_candidates.append(claimed_prompt)

    seen_queued_prompt = False
    seen_real_prompt = False
    for raw_line in text.splitlines():
        try:
            record = json.loads(raw_line)
        except Exception:
            continue
        if not isinstance(record, dict):
            continue
        record_type = str(record.get("type") or "")
        if seen_real_prompt and _channel_transcript_is_assistant_message(record):
            return "completed"
        if record_type == "queue-operation" and record.get("operation") == "enqueue":
            raw = record.get("content")
            if isinstance(raw, str) and _channel_prompt_references_message_id(raw, message_id, prompt_candidates):
                seen_queued_prompt = True
            continue
        if record_type == "attachment":
            attachment = record.get("attachment")
            if isinstance(attachment, dict) and attachment.get("type") == "queued_command":
                raw = attachment.get("prompt")
                if isinstance(raw, str) and _channel_prompt_references_message_id(raw, message_id, prompt_candidates):
                    seen_queued_prompt = True
            continue
        # A queued_command attachment only means Claude Code accepted text into
        # its line editor queue.  It is not a real user turn and can be
        # superseded by later typed/queued prompts.  Only commit delivery after
        # the prompt is present as an actual user message.
        content_text = _channel_transcript_user_text(record)
        if _channel_prompt_references_message_id(content_text, message_id, prompt_candidates):
            seen_real_prompt = True
    if seen_real_prompt:
        return "pending"
    return "queued" if seen_queued_prompt else "missing"


def _channel_message_content_blocks(message: dict[str, Any]) -> list[dict[str, Any]]:
    content = message.get("content")
    if isinstance(content, dict):
        return [content]
    if isinstance(content, list):
        return [item for item in content if isinstance(item, dict)]
    return []


def _channel_tool_use_ids_from_message(message: dict[str, Any]) -> set[str]:
    ids: set[str] = set()
    for block in _channel_message_content_blocks(message):
        if block.get("type") != "tool_use":
            continue
        tool_id = str(block.get("id") or "").strip()
        if tool_id:
            ids.add(tool_id)
    return ids


def _channel_tool_result_ids_from_message(message: dict[str, Any]) -> set[str]:
    ids: set[str] = set()
    for block in _channel_message_content_blocks(message):
        if block.get("type") != "tool_result":
            continue
        tool_id = str(block.get("tool_use_id") or "").strip()
        if tool_id:
            ids.add(tool_id)
    return ids


def _channel_stdin_active_tool_call_from_text(text: str) -> bool:
    pending_tool_ids: set[str] = set()
    unknown_tool_active = False
    for raw_line in text.splitlines():
        try:
            record = json.loads(raw_line)
        except Exception:
            continue
        if not isinstance(record, dict):
            continue
        record_type = str(record.get("type") or "")
        message = record.get("message")
        message_obj = message if isinstance(message, dict) else {}
        message_role = str(message_obj.get("role") or "")
        payload = record.get("payload")
        payload_obj = payload if isinstance(payload, dict) else {}
        payload_type = str(payload_obj.get("type") or "")
        if record_type == "response_item":
            if payload_type in {"function_call", "custom_tool_call", "local_shell_call"}:
                tool_id = _channel_transcript_tool_call_id(payload_obj)
                if tool_id:
                    pending_tool_ids.add(tool_id)
                else:
                    unknown_tool_active = True
                continue
            if payload_type in {"function_call_output", "custom_tool_call_output", "local_shell_call_output"}:
                tool_id = _channel_transcript_tool_call_id(payload_obj)
                if tool_id:
                    pending_tool_ids.discard(tool_id)
                else:
                    pending_tool_ids.clear()
                unknown_tool_active = False
                continue
            if _channel_transcript_is_assistant_message(record):
                pending_tool_ids.clear()
                unknown_tool_active = False
                continue
        if record_type == "event_msg":
            if payload_type in {"mcp_tool_call_begin", "tool_call_begin"}:
                tool_id = _channel_transcript_tool_call_id(payload_obj)
                if tool_id:
                    pending_tool_ids.add(tool_id)
                else:
                    unknown_tool_active = True
                continue
            if payload_type in {"mcp_tool_call_end", "tool_call_end"}:
                tool_id = _channel_transcript_tool_call_id(payload_obj)
                if tool_id:
                    pending_tool_ids.discard(tool_id)
                else:
                    pending_tool_ids.clear()
                unknown_tool_active = False
                continue
        if record_type == "assistant" or message_role == "assistant":
            tool_use_ids = _channel_tool_use_ids_from_message(message_obj)
            if str(message_obj.get("stop_reason") or "") == "tool_use" or tool_use_ids:
                pending_tool_ids.update(tool_use_ids)
                if not tool_use_ids:
                    unknown_tool_active = True
            else:
                pending_tool_ids.clear()
                unknown_tool_active = False
            continue
        if record_type == "user" or message_role == "user":
            tool_result_ids = _channel_tool_result_ids_from_message(message_obj)
            if tool_result_ids:
                pending_tool_ids.difference_update(tool_result_ids)
                unknown_tool_active = False
            elif record.get("toolUseResult") is not None:
                pending_tool_ids.clear()
                unknown_tool_active = False
    return bool(pending_tool_ids or unknown_tool_active)


def _channel_stdin_active_tool_call() -> bool:
    path = _latest_claude_transcript_path()
    if path is None:
        return False
    text = _read_file_tail_text(path)
    if not text:
        return False
    return _channel_stdin_active_tool_call_from_text(text)


def _channel_stdin_active_turn_from_text(text: str) -> bool:
    active = False
    for raw_line in text.splitlines():
        try:
            record = json.loads(raw_line)
        except Exception:
            continue
        if not isinstance(record, dict):
            continue
        payload = record.get("payload")
        payload_obj = payload if isinstance(payload, dict) else {}
        event_type = str(payload_obj.get("type") or record.get("type") or "")
        if event_type in {"task_started", "turn_started"}:
            active = True
        elif event_type in {"task_complete", "turn_complete", "turn_aborted"}:
            active = False
    return active


def _channel_stdin_active_turn() -> bool:
    path = _latest_claude_transcript_path()
    if path is None:
        return False
    text = _read_file_tail_text(path)
    if not text:
        return False
    return _channel_stdin_active_turn_from_text(text)


def _channel_stdin_wake_completed(message_id: int) -> bool:
    return _channel_stdin_wake_state(message_id) == "completed"


def _channel_stdin_queued_command_ids_from_text(text: str) -> set[int]:
    ids: set[int] = set()
    for raw_line in text.splitlines():
        try:
            record = json.loads(raw_line)
        except Exception:
            continue
        if not isinstance(record, dict):
            continue
        candidate = ""
        if record.get("type") == "queue-operation" and record.get("operation") == "enqueue":
            raw = record.get("content")
            if isinstance(raw, str):
                candidate = raw
        elif record.get("type") == "attachment":
            attachment = record.get("attachment")
            if isinstance(attachment, dict) and attachment.get("type") == "queued_command":
                raw = attachment.get("prompt")
                if isinstance(raw, str):
                    candidate = raw
        if not candidate:
            continue
        ids.update(_channel_prompt_message_ids(candidate))
    return ids


def _channel_stdin_recover_cursor_from_queued_only(last_id: int) -> int:
    if last_id <= 0:
        return last_id
    path = _latest_claude_transcript_path()
    if path is None:
        return last_id
    try:
        stat = path.stat()
        marker = (str(path), int(stat.st_mtime_ns), int(stat.st_size))
    except OSError:
        return last_id
    now = time.time()
    cached_marker = _CHANNEL_STDIN_RECOVERY_CACHE.get("marker")
    if (
        _CHANNEL_STDIN_RECOVERY_CACHE.get("last_id") == last_id
        and cached_marker == marker
        and now - float(_CHANNEL_STDIN_RECOVERY_CACHE.get("checked_at") or 0.0) < 5.0
    ):
        cached = _CHANNEL_STDIN_RECOVERY_CACHE.get("recovered_last_id")
        recovered = int(cached) if isinstance(cached, int) else last_id
        return _channel_llm_clamp_to_clear_floor(recovered)
    text = _read_file_tail_text(path, max_bytes=8 * 1024 * 1024)
    recovered = last_id
    if text:
        for message_id in sorted(_channel_stdin_queued_command_ids_from_text(text)):
            if message_id > last_id:
                continue
            if _channel_stdin_wake_state_from_text(message_id, text) == "missing":
                recovered = max(0, message_id - 1)
                router_log(
                    "WARN",
                    f"channel_stdin_proxy_recover_queued_only message_id={message_id} cursor={last_id} recovered_cursor={recovered}",
                )
                break
    _CHANNEL_STDIN_RECOVERY_CACHE.update(
        {
            "checked_at": now,
            "last_id": last_id,
            "marker": marker,
            "recovered_last_id": recovered,
        }
    )
    return _channel_llm_clamp_to_clear_floor(recovered)


def _channel_stdin_unseen_retry_seconds() -> float:
    raw = os.environ.get("CIEL_RUNTIME_CHANNEL_WAKE_UNSEEN_RETRY_SECONDS")
    if raw is None:
        return 20.0
    try:
        return max(2.0, min(300.0, float(raw)))
    except Exception:
        return 20.0


def _channel_stdin_inflight_stale_seconds() -> float:
    raw = os.environ.get("CIEL_RUNTIME_CHANNEL_WAKE_INFLIGHT_STALE_SECONDS")
    if raw is None:
        return 180.0
    try:
        return max(30.0, min(1800.0, float(raw)))
    except Exception:
        return 180.0


def _channel_stdin_inflight_is_stale(state: str, started_at: float, now: float | None = None) -> bool:
    if state not in {"queued", "unknown"} or started_at <= 0:
        return False
    current = time.time() if now is None else float(now)
    return current - started_at >= _channel_stdin_inflight_stale_seconds()


def _channel_stdin_should_check_pending(
    marker: tuple[float, int],
    last_marker: tuple[float, int],
    force_recheck: bool,
    channel_inflight_id: int | None,
) -> bool:
    return force_recheck or marker != last_marker


def _inject_pending_channel_messages(
    master_fd: int,
    last_id: int,
    enter_bytes: bytes | None = None,
    *,
    web_chat_only: bool = False,
    wake_for_llm_delivery: bool = False,
    commit_cursor: bool = True,
    injected_message_ids: list[int] | None = None,
    submit_retry_count: int = 1,
    confirm_submit: bool = False,
    bracketed_paste: bool = False,
    submit_delay_seconds: float | None = None,
    skip_blocking_wake_states: bool = False,
) -> int:
    with _CHANNEL_STDIN_INJECT_LOCK:
        if _channel_stdin_active_tool_call():
            router_log("INFO", f"channel_stdin_proxy_deferred cursor={last_id} reason=active_tool_call")
            return last_id
        if _channel_stdin_active_turn():
            router_log("INFO", f"channel_stdin_proxy_deferred cursor={last_id} reason=active_turn")
            return last_id
        if not web_chat_only:
            last_id = _channel_stdin_recover_cursor_from_queued_only(last_id)
        pending: list[dict[str, Any]] = []
        return_last_id = last_id
        candidates = read_chat_messages(last_id, None, None, _channel_pending_scan_limit())
        superseded_ids = _channel_superseded_message_ids(candidates)
        batch_limit = _channel_stdin_wake_batch_limit() if wake_for_llm_delivery else 1
        seen_event_keys: set[tuple[str, ...]] = set()
        for message in candidates:
            previous_last_id = last_id
            try:
                message_id = int(message.get("id") or 0)
                last_id = max(last_id, message_id)
            except Exception:
                continue
            if web_chat_only and not _channel_message_is_web_chat_request(message):
                router_log(
                    "INFO",
                    f"channel_stdin_proxy_skipped_noise message_id={message.get('id')} channel={message.get('channel')} reason=not_web_chat",
                )
                continue
            skip_reason = _channel_llm_message_skip_reason(message)
            if skip_reason:
                router_log(
                    "INFO",
                    f"channel_stdin_proxy_skipped_noise message_id={message.get('id')} channel={message.get('channel')} reason={skip_reason}",
                )
                continue
            if message_id in superseded_ids:
                router_log(
                    "INFO",
                    f"channel_stdin_proxy_skipped_noise message_id={message.get('id')} channel={message.get('channel')} reason=superseded_channel_notice",
                )
                continue
            event_key = _channel_message_event_identity_key(message)
            if event_key and event_key in seen_event_keys:
                router_log(
                    "INFO",
                    f"channel_stdin_proxy_skipped_noise message_id={message.get('id')} channel={message.get('channel')} reason=duplicate_channel_event",
                )
                continue
            if wake_for_llm_delivery:
                message_prompt = format_channel_llm_delivery_wake_prompt([message])
            elif web_chat_only and _channel_message_is_web_chat_request(message):
                message_prompt = format_channel_web_chat_wake_batch_prompt([message])
            else:
                message_prompt = format_channel_wake_batch_prompt([message])
            wake_state = _channel_stdin_wake_state_for_message(message, message_prompt)
            if wake_state == "completed":
                router_log(
                    "INFO",
                    f"channel_stdin_proxy_skipped_noise message_id={message.get('id')} channel={message.get('channel')} reason=stdin_wake_completed",
                )
                continue
            if skip_blocking_wake_states and wake_state == "missing" and _channel_stdin_wake_claim_prompt(message_id):
                router_log(
                    "INFO",
                    f"channel_stdin_proxy_skipped_noise message_id={message.get('id')} channel={message.get('channel')} reason=stdin_wake_claimed_continue",
                )
                continue
            if wake_state in {"pending", "queued"}:
                if wake_state == "queued" and _channel_stdin_wake_queued_is_stale_for_message(message, message_prompt):
                    with _CHANNEL_STDIN_WAKE_LOCK:
                        _CHANNEL_STDIN_WAKE_DELIVERED.discard(message_id)
                        _CHANNEL_STDIN_WAKE_PROMPTS.pop(message_id, None)
                    _channel_stdin_clear_wake_claim(message_id)
                    if not web_chat_only:
                        _commit_channel_llm_cursor_if_newer(message_id)
                    router_log(
                        "WARN",
                        f"channel_stdin_proxy_skipped_noise message_id={message.get('id')} channel={message.get('channel')} reason=stale_queued_wake",
                    )
                    continue
                if skip_blocking_wake_states:
                    router_log(
                        "INFO",
                        f"channel_stdin_proxy_skipped_noise message_id={message.get('id')} channel={message.get('channel')} reason=stdin_wake_{wake_state}_continue",
                    )
                    continue
                router_log(
                    "INFO",
                    f"channel_stdin_proxy_waiting_for_turn_completion message_id={message.get('id')} channel={message.get('channel')} state={wake_state}",
                )
                if pending:
                    break
                return previous_last_id
            if not wake_for_llm_delivery:
                with _CHANNEL_STDIN_WAKE_LOCK:
                    if message_id in _CHANNEL_STDIN_WAKE_DELIVERED:
                        router_log(
                            "INFO",
                            f"channel_stdin_proxy_skipped_noise message_id={message.get('id')} channel={message.get('channel')} reason=stdin_wake_delivered",
                        )
                        continue
                    _CHANNEL_STDIN_WAKE_DELIVERED.add(message_id)
                    if len(_CHANNEL_STDIN_WAKE_DELIVERED) > 1000:
                        for old_id in sorted(_CHANNEL_STDIN_WAKE_DELIVERED)[:500]:
                            _CHANNEL_STDIN_WAKE_DELIVERED.discard(old_id)
            pending.append(message)
            if event_key:
                seen_event_keys.add(event_key)
            if wake_for_llm_delivery and len(pending) == 1:
                return_last_id = previous_last_id
            last_id = message_id
            if len(pending) >= batch_limit:
                break
        if pending:
            if wake_for_llm_delivery:
                prompt = format_channel_llm_delivery_wake_prompt(pending)
            elif web_chat_only and all(_channel_message_is_web_chat_request(message) for message in pending):
                prompt = format_channel_web_chat_wake_batch_prompt(pending)
            else:
                prompt = format_channel_wake_batch_prompt(pending)
            claimed_ids: list[int] = []
            if wake_for_llm_delivery:
                for message in pending:
                    try:
                        claim_id = int(message.get("id") or 0)
                    except Exception:
                        continue
                    if claim_id <= 0:
                        continue
                    if not _channel_stdin_claim_wake_prompt(claim_id, prompt):
                        router_log(
                            "INFO",
                            f"channel_stdin_proxy_skipped_noise message_id={claim_id} channel={message.get('channel')} reason=stdin_wake_claimed",
                        )
                        return return_last_id
                    claimed_ids.append(claim_id)
            submit_bytes = _channel_wake_enter_bytes(enter_bytes)
            try:
                _write_channel_wake_prompt(
                    master_fd,
                    prompt,
                    submit_bytes,
                    submit_retry_count=submit_retry_count,
                    confirm_submit=confirm_submit,
                    bracketed_paste=bracketed_paste,
                    submit_delay_seconds=submit_delay_seconds,
                )
                with _CHANNEL_STDIN_WAKE_LOCK:
                    for message in pending:
                        try:
                            message_id_for_prompt = int(message.get("id") or 0)
                        except Exception:
                            continue
                        if message_id_for_prompt > 0:
                            _CHANNEL_STDIN_WAKE_PROMPTS[message_id_for_prompt] = prompt
                    if len(_CHANNEL_STDIN_WAKE_PROMPTS) > 1000:
                        for old_id in sorted(_CHANNEL_STDIN_WAKE_PROMPTS)[:500]:
                            _CHANNEL_STDIN_WAKE_PROMPTS.pop(old_id, None)
            except Exception:
                with _CHANNEL_STDIN_WAKE_LOCK:
                    for message in pending:
                        try:
                            failed_id = int(message.get("id") or 0)
                        except Exception:
                            continue
                        _CHANNEL_STDIN_WAKE_DELIVERED.discard(failed_id)
                        _CHANNEL_STDIN_WAKE_PROMPTS.pop(failed_id, None)
                        _channel_stdin_clear_wake_claim(failed_id)
                for failed_id in claimed_ids:
                    _channel_stdin_clear_wake_claim(failed_id)
                raise
            if not web_chat_only:
                if commit_cursor:
                    _commit_channel_llm_cursor_if_newer(last_id)
                if injected_message_ids is not None:
                    injected_message_ids.extend(
                        int(message.get("id") or 0)
                        for message in pending
                        if int(message.get("id") or 0) > 0
                    )
            ids = ",".join(str(message.get("id") or "") for message in pending)
            channels = ",".join(sorted({str(message.get("channel") or "default") for message in pending}))
            router_log(
                "INFO",
                f"channel_stdin_proxy_injected count={len(pending)} message_ids={ids} channels={channels} enter={_channel_enter_label(submit_bytes)} commit_cursor={commit_cursor}",
            )
        return return_last_id if pending and wake_for_llm_delivery else last_id


def _inject_pending_compact_request(
    master_fd: int,
    enter_bytes: bytes | None = None,
    *,
    log_defer: bool = True,
    submit_retry_count: int = 1,
    confirm_submit: bool = False,
    bracketed_paste: bool = False,
    submit_delay_seconds: float | None = None,
) -> str:
    request = _read_channel_compact_request()
    if not request:
        return "none"
    request_id = str(request.get("id") or "")
    if _channel_stdin_active_tool_call():
        if log_defer:
            router_log("INFO", f"channel_compact_request_deferred id={request_id or '-'} reason=active_tool_call")
        return "deferred"
    if _channel_stdin_active_turn():
        if log_defer:
            router_log("INFO", f"channel_compact_request_deferred id={request_id or '-'} reason=active_turn")
        return "deferred"
    command = str(request.get("command") or "/compact").strip() or "/compact"
    if command != "/compact":
        command = "/compact"
    submit_bytes = _channel_wake_enter_bytes(enter_bytes)
    _write_channel_wake_prompt(
        master_fd,
        command,
        submit_bytes,
        submit_retry_count=submit_retry_count,
        confirm_submit=confirm_submit,
        bracketed_paste=bracketed_paste,
        submit_delay_seconds=submit_delay_seconds,
    )
    _clear_channel_compact_request(request_id or None)
    router_log(
        "INFO",
        f"channel_compact_request_injected id={request_id or '-'} enter={_channel_enter_label(submit_bytes)}",
    )
    return "injected"


def _chat_messages_file_marker() -> tuple[float, int]:
    try:
        stat = CHAT_MESSAGES_PATH.stat()
        return (stat.st_mtime, stat.st_size)
    except Exception:
        return (0.0, 0)


def _terminal_winsize_from_fd(fd: int) -> tuple[int, int]:
    """Return terminal size as (rows, columns), never 0x0."""
    try:
        size = os.get_terminal_size(fd)
        rows = int(size.lines)
        cols = int(size.columns)
    except Exception:
        rows = 0
        cols = 0
    if rows > 0 and cols > 0:
        return rows, cols
    fallback = shutil.get_terminal_size((80, 24))
    rows = int(getattr(fallback, "lines", 0) or 0)
    cols = int(getattr(fallback, "columns", 0) or 0)
    if rows <= 0:
        rows = 24
    if cols <= 0:
        cols = 80
    return rows, cols


def _apply_pty_winsize(pty_fd: int, rows: int, cols: int) -> bool:
    if os.name != "posix" or rows <= 0 or cols <= 0:
        return False
    try:
        import fcntl
        import struct
        import termios

        fcntl.ioctl(pty_fd, termios.TIOCSWINSZ, struct.pack("HHHH", rows, cols, 0, 0))
        return True
    except Exception:
        return False


TERMINAL_INPUT_MODE_RESET = "\x1b[?1000l\x1b[?1002l\x1b[?1003l\x1b[?1004l\x1b[?1005l\x1b[?1006l\x1b[?1015l"


def _terminal_input_mode_reset_enabled() -> bool:
    # On Windows cmd/conhost, DECSET mouse reset sequences can be printed
    # literally. The Windows launch path uses SetConsoleMode instead.
    if os.name == "nt" and os.environ.get("CIEL_RUNTIME_TERMINAL_INPUT_MODE_RESET") is None:
        return False
    return parse_bool(os.environ.get("CIEL_RUNTIME_TERMINAL_INPUT_MODE_RESET"), True)


def _terminal_input_mode_reset_interval_seconds(default: float = 2.0) -> float:
    raw = os.environ.get("CIEL_RUNTIME_TERMINAL_INPUT_MODE_RESET_INTERVAL_SECONDS")
    if raw is None:
        return default
    try:
        return max(0.25, min(60.0, float(raw)))
    except Exception:
        return default


def _write_terminal_input_mode_reset(stream: Any | None = None) -> None:
    if not _terminal_input_mode_reset_enabled():
        return
    target = stream if stream is not None else sys.stdout
    try:
        if hasattr(target, "isatty") and not target.isatty():
            return
        target.write(TERMINAL_INPUT_MODE_RESET)
        target.flush()
    except Exception:
        return


class _TerminalMouseInputFilter:
    """Strip terminal mouse reports that can leak into TUI prompt buffers."""

    def __init__(self) -> None:
        self._pending = b""

    def feed(self, data: bytes) -> bytes:
        if not data:
            return b""
        buf = self._pending + data
        self._pending = b""
        out = bytearray()
        i = 0
        while i < len(buf):
            if buf[i] != 0x1B:
                out.append(buf[i])
                i += 1
                continue
            if i + 1 >= len(buf):
                self._pending = buf[i:]
                break
            if buf[i + 1] != ord("["):
                out.append(buf[i])
                i += 1
                continue
            if i + 2 >= len(buf):
                self._pending = buf[i:]
                break
            marker = buf[i + 2]
            if marker == ord("<"):
                j = i + 3
                while j < len(buf) and (48 <= buf[j] <= 57 or buf[j] == ord(";")):
                    j += 1
                if j >= len(buf):
                    self._pending = buf[i:]
                    break
                if j > i + 3 and buf[j] in (ord("M"), ord("m")):
                    i = j + 1
                    continue
                out.append(buf[i])
                i += 1
                continue
            if marker == ord("M"):
                if i + 6 <= len(buf):
                    i += 6
                    continue
                self._pending = buf[i:]
                break
            if 48 <= marker <= 57:
                j = i + 2
                semicolons = 0
                while j < len(buf) and (48 <= buf[j] <= 57 or buf[j] == ord(";")):
                    if buf[j] == ord(";"):
                        semicolons += 1
                    j += 1
                if j >= len(buf):
                    self._pending = buf[i:]
                    break
                if semicolons >= 2 and buf[j] in (ord("M"), ord("m")):
                    i = j + 1
                    continue
                out.append(buf[i])
                i += 1
                continue
            out.append(buf[i])
            i += 1
        return bytes(out)

    def flush(self) -> bytes:
        pending = self._pending
        self._pending = b""
        return pending


def _strip_terminal_mouse_input_reports(data: bytes) -> bytes:
    filt = _TerminalMouseInputFilter()
    return filt.feed(data) + filt.flush()


_WINDOWS_CONSOLE_INPUT_FALLBACK_HANDLE: Any = None


def _windows_console_input_handle() -> Any:
    global _WINDOWS_CONSOLE_INPUT_FALLBACK_HANDLE
    if os.name != "nt":
        return None
    try:
        import ctypes
        from ctypes import wintypes

        kernel32 = ctypes.WinDLL("kernel32", use_last_error=True)
        kernel32.GetStdHandle.argtypes = [wintypes.DWORD]
        kernel32.GetStdHandle.restype = wintypes.HANDLE
        kernel32.GetConsoleMode.argtypes = [wintypes.HANDLE, ctypes.POINTER(wintypes.DWORD)]
        kernel32.GetConsoleMode.restype = wintypes.BOOL
        handle = kernel32.GetStdHandle(wintypes.DWORD(-10 & 0xFFFFFFFF))
        handle_value = int(handle) if isinstance(handle, int) else int(getattr(handle, "value", 0) or 0)
        invalid_handle = int(ctypes.c_void_p(-1).value or -1)
        if handle_value and handle_value != invalid_handle:
            mode = wintypes.DWORD(0)
            if kernel32.GetConsoleMode(handle, ctypes.byref(mode)):
                return handle

        cached = _WINDOWS_CONSOLE_INPUT_FALLBACK_HANDLE
        cached_value = int(cached) if isinstance(cached, int) else int(getattr(cached, "value", 0) or 0)
        if cached_value and cached_value != invalid_handle:
            mode = wintypes.DWORD(0)
            if kernel32.GetConsoleMode(cached, ctypes.byref(mode)):
                return cached

        kernel32.CreateFileW.argtypes = [
            wintypes.LPCWSTR,
            wintypes.DWORD,
            wintypes.DWORD,
            wintypes.LPVOID,
            wintypes.DWORD,
            wintypes.DWORD,
            wintypes.HANDLE,
        ]
        kernel32.CreateFileW.restype = wintypes.HANDLE
        console_handle = kernel32.CreateFileW(
            "CONIN$",
            0x80000000 | 0x40000000,
            0x00000001 | 0x00000002,
            None,
            3,
            0,
            None,
        )
        console_value = (
            int(console_handle)
            if isinstance(console_handle, int)
            else int(getattr(console_handle, "value", 0) or 0)
        )
        if not console_value or console_value == invalid_handle:
            return None
        mode = wintypes.DWORD(0)
        if not kernel32.GetConsoleMode(console_handle, ctypes.byref(mode)):
            return None
        _WINDOWS_CONSOLE_INPUT_FALLBACK_HANDLE = console_handle
        return console_handle
    except Exception:
        return None


def _windows_console_input_supported() -> bool:
    # Python's isatty() can be false through npm.cmd -> py.exe launch chains even
    # when the process is attached to a real Windows console. GetConsoleMode is
    # the authoritative check and rejects redirected pipe/file handles.
    return _windows_console_input_mode() is not None


def _windows_console_mouse_input_filter_enabled() -> bool:
    return parse_bool(os.environ.get("CIEL_RUNTIME_WINDOWS_CONSOLE_MOUSE_FILTER"), True)


def _windows_console_input_mode() -> int | None:
    handle = _windows_console_input_handle()
    if handle is None:
        return None
    try:
        import ctypes
        from ctypes import wintypes

        mode = wintypes.DWORD(0)
        kernel32 = ctypes.WinDLL("kernel32", use_last_error=True)
        kernel32.GetConsoleMode.argtypes = [wintypes.HANDLE, ctypes.POINTER(wintypes.DWORD)]
        kernel32.GetConsoleMode.restype = wintypes.BOOL
        ok = kernel32.GetConsoleMode(handle, ctypes.byref(mode))
        if not ok:
            return None
        return int(mode.value)
    except Exception:
        return None


def _set_windows_console_input_mode(mode: int) -> bool:
    handle = _windows_console_input_handle()
    if handle is None:
        return False
    try:
        import ctypes
        from ctypes import wintypes

        kernel32 = ctypes.WinDLL("kernel32", use_last_error=True)
        kernel32.SetConsoleMode.argtypes = [wintypes.HANDLE, wintypes.DWORD]
        kernel32.SetConsoleMode.restype = wintypes.BOOL
        ok = kernel32.SetConsoleMode(handle, wintypes.DWORD(int(mode)))
        return bool(ok)
    except Exception:
        return False


class _WindowsConsoleMouseInputGuard:
    ENABLE_MOUSE_INPUT = 0x0010

    def __init__(self) -> None:
        self.original_mode: int | None = None

    def apply(self) -> None:
        if os.name != "nt" or not _windows_console_mouse_input_filter_enabled():
            return
        current = _windows_console_input_mode()
        if current is None:
            return
        if self.original_mode is None:
            self.original_mode = current
        filtered = current & ~self.ENABLE_MOUSE_INPUT
        if filtered != current and _set_windows_console_input_mode(filtered):
            router_log("INFO", f"windows_console_mouse_input_disabled mode={current:#x}->{filtered:#x}")

    def restore(self) -> None:
        if os.name != "nt" or self.original_mode is None:
            return
        _set_windows_console_input_mode(self.original_mode)


def _windows_console_utf16_units(chars: Iterable[str]) -> list[str]:
    """Expand non-BMP code points into WCHAR-sized UTF-16 surrogate units."""
    units: list[str] = []
    for ch in chars:
        codepoint = ord(ch)
        if codepoint > 0xFFFF:
            codepoint -= 0x10000
            units.extend((chr(0xD800 + (codepoint >> 10)), chr(0xDC00 + (codepoint & 0x3FF))))
        else:
            units.append(ch)
    return units


class _WindowsConsoleInputWriter:
    """Inject keystrokes into the active Windows console input queue."""

    def __init__(self) -> None:
        self.handle = _windows_console_input_handle()
        if self.handle is None:
            raise RuntimeError("Windows console input handle is not available")
        self._mouse_filter = _TerminalMouseInputFilter()
        self._queue_baseline: int | None = None

    def wait_until_input_consumed(self, timeout_seconds: float = 2.0) -> bool:
        """Wait until the most recently written console-input batch leaves the queue."""
        if self._queue_baseline is None:
            return True
        import ctypes
        from ctypes import wintypes

        kernel32 = ctypes.WinDLL("kernel32", use_last_error=True)
        kernel32.GetNumberOfConsoleInputEvents.argtypes = [wintypes.HANDLE, ctypes.POINTER(wintypes.DWORD)]
        kernel32.GetNumberOfConsoleInputEvents.restype = wintypes.BOOL
        deadline = time.monotonic() + max(0.0, timeout_seconds)
        while True:
            pending = wintypes.DWORD(0)
            if not kernel32.GetNumberOfConsoleInputEvents(self.handle, ctypes.byref(pending)):
                return False
            if int(pending.value) <= self._queue_baseline:
                return True
            if time.monotonic() >= deadline:
                return False
            time.sleep(0.01)

    def write(self, data: bytes) -> None:
        if not data:
            return
        data = self._mouse_filter.feed(data)
        if not data:
            return
        text = data.decode("utf-8", errors="replace")
        chars: list[str] = []
        i = 0
        while i < len(text):
            ch = text[i]
            if ch == "\r" and i + 1 < len(text) and text[i + 1] == "\n":
                chars.append("\r")
                i += 2
                continue
            if ch == "\n":
                chars.append("\r")
            else:
                chars.append(ch)
            i += 1
        self._write_chars(chars)

    def _write_chars(self, chars: list[str]) -> None:
        import ctypes
        from ctypes import wintypes

        if not chars:
            return
        kernel32 = ctypes.WinDLL("kernel32", use_last_error=True)
        user32 = ctypes.WinDLL("user32", use_last_error=True)

        class KEY_EVENT_RECORD(ctypes.Structure):
            _fields_ = [
                ("bKeyDown", wintypes.BOOL),
                ("wRepeatCount", wintypes.WORD),
                ("wVirtualKeyCode", wintypes.WORD),
                ("wVirtualScanCode", wintypes.WORD),
                ("uChar", wintypes.WCHAR),
                ("dwControlKeyState", wintypes.DWORD),
            ]

        class EVENT_UNION(ctypes.Union):
            _fields_ = [("KeyEvent", KEY_EVENT_RECORD)]

        class INPUT_RECORD(ctypes.Structure):
            _fields_ = [("EventType", wintypes.WORD), ("Event", EVENT_UNION)]

        user32.MapVirtualKeyW.argtypes = [wintypes.UINT, wintypes.UINT]
        user32.MapVirtualKeyW.restype = wintypes.UINT
        kernel32.WriteConsoleInputW.argtypes = [
            wintypes.HANDLE,
            ctypes.POINTER(INPUT_RECORD),
            wintypes.DWORD,
            ctypes.POINTER(wintypes.DWORD),
        ]
        kernel32.WriteConsoleInputW.restype = wintypes.BOOL
        kernel32.GetNumberOfConsoleInputEvents.argtypes = [
            wintypes.HANDLE,
            ctypes.POINTER(wintypes.DWORD),
        ]
        kernel32.GetNumberOfConsoleInputEvents.restype = wintypes.BOOL

        KEY_EVENT = 0x0001
        LEFT_CTRL_PRESSED = 0x0008
        MAPVK_VK_TO_VSC = 0
        vk_map = {
            "\r": 0x0D,
            "\x1b": 0x1B,
            "\x08": 0x08,
            "\t": 0x09,
            "\x15": 0x55,
        }
        records: list[Any] = []
        for ch in _windows_console_utf16_units(chars):
            vk = vk_map.get(ch)
            if vk is None and len(ch) == 1 and "A" <= ch.upper() <= "Z":
                vk = ord(ch.upper())
            elif vk is None:
                vk = 0
            control = LEFT_CTRL_PRESSED if ch == "\x15" else 0
            scan_code = int(user32.MapVirtualKeyW(int(vk), MAPVK_VK_TO_VSC)) if vk else 0
            for key_down in (True, False):
                record = INPUT_RECORD()
                record.EventType = KEY_EVENT
                record.Event.KeyEvent = KEY_EVENT_RECORD(
                    bool(key_down),
                    1,
                    int(vk),
                    scan_code,
                    ch,
                    control,
                )
                records.append(record)
        array_type = INPUT_RECORD * len(records)
        written = wintypes.DWORD(0)
        pending_before = wintypes.DWORD(0)
        if kernel32.GetNumberOfConsoleInputEvents(self.handle, ctypes.byref(pending_before)):
            self._queue_baseline = int(pending_before.value)
        else:
            self._queue_baseline = None
        ok = kernel32.WriteConsoleInputW(self.handle, array_type(*records), len(records), ctypes.byref(written))
        if not ok or int(written.value) != len(records):
            raise OSError(f"WriteConsoleInputW failed: written={int(written.value)} expected={len(records)}")


def _retry_windows_console_channel_submit(
    writer: Any,
    enter_bytes: bytes,
    state: str,
    attempts: int,
    retry_count: int,
    last_attempt_at: float,
    now: float,
    *,
    confirm_submit: bool,
    turn_active: bool = False,
) -> tuple[int, float]:
    if not confirm_submit or turn_active or state != "missing" or attempts >= retry_count:
        return attempts, last_attempt_at
    if now - last_attempt_at < _channel_wake_submit_retry_delay_seconds():
        return attempts, last_attempt_at
    _write_fd_all(writer, enter_bytes)
    next_attempt = attempts + 1
    router_log("INFO", f"channel_windows_console_submit_retry attempt={next_attempt}/{retry_count}")
    return next_attempt, now


def subprocess_call_with_windows_console_wake_proxy(
    cmd: list[str],
    env: dict[str, str],
    *,
    inject_channel_messages: bool = True,
    inject_web_chat_only: bool = False,
    wake_for_llm_delivery: bool = False,
    synthetic_enter_bytes: str | bytes | None = None,
    normalize_bare_cr_for_synthetic_enter: bool = True,
    channel_wake_submit_retries: int = 1,
    channel_wake_confirm_submit: bool = False,
    channel_wake_bracketed_paste: bool = False,
    channel_wake_submit_delay_seconds: float | None = None,
    tracked_child_pid_path: Path | None = None,
) -> int:
    _write_terminal_input_mode_reset()
    input_mode_guard = _WindowsConsoleMouseInputGuard()
    input_mode_guard.apply()
    proc = subprocess.Popen(cmd, env=env)
    _write_codex_child_process_record(tracked_child_pid_path, proc.pid, cmd)
    writer = _WindowsConsoleInputWriter()
    last_id = ensure_channel_llm_delivery_cursor_initialized()
    last_channel_marker: tuple[float, int] = (0.0, -1)
    last_channel_poll = 0.0
    last_compact_poll = 0.0
    channel_inflight_id: int | None = None
    channel_inflight_cursor: int | None = None
    channel_inflight_logged_at = 0.0
    channel_inflight_started_at = 0.0
    channel_submit_attempts = 0
    channel_last_submit_at = 0.0
    channel_pending_recheck = False
    channel_tool_defer_logged_at = 0.0
    compact_defer_logged_at = 0.0
    channel_enter_bytes = _channel_wake_enter_bytes(synthetic_enter_bytes)
    channel_input_ready_at = time.time() + _windows_channel_startup_grace_seconds()
    # Crossterm's Windows backend reads INPUT_RECORD key events directly. ANSI
    # bracketed-paste delimiters would arrive as Esc + literal characters, not
    # as Event::Paste, so only the POSIX byte-stream proxy may use them.
    windows_bracketed_paste = False
    submit_retry_count = max(1, min(8, int(channel_wake_submit_retries or 1)))
    last_terminal_input_mode_reset = 0.0
    terminal_input_mode_reset_interval = _terminal_input_mode_reset_interval_seconds(0.25)
    router_log(
        "INFO",
        "channel_windows_console_proxy_started "
        f"pid={proc.pid} enter={_channel_enter_label(channel_enter_bytes)} "
        f"submit_retries={submit_retry_count} confirm_submit={bool(channel_wake_confirm_submit)} "
        f"bracketed_paste={windows_bracketed_paste}",
    )
    try:
        while proc.poll() is None:
            now = time.time()
            if now - last_terminal_input_mode_reset >= terminal_input_mode_reset_interval:
                last_terminal_input_mode_reset = now
                _write_terminal_input_mode_reset()
                input_mode_guard.apply()
            if channel_inflight_id is not None:
                channel_inflight_state = _channel_stdin_wake_state(channel_inflight_id)
                channel_turn_active = _channel_stdin_active_turn()
                channel_submit_attempts, channel_last_submit_at = _retry_windows_console_channel_submit(
                    writer,
                    channel_enter_bytes,
                    channel_inflight_state,
                    channel_submit_attempts,
                    submit_retry_count,
                    channel_last_submit_at,
                    now,
                    confirm_submit=channel_wake_confirm_submit,
                    turn_active=channel_turn_active,
                )
                if channel_inflight_state == "completed":
                    if channel_inflight_cursor is not None:
                        _commit_channel_llm_cursor_if_newer(channel_inflight_cursor)
                    with _CHANNEL_STDIN_WAKE_LOCK:
                        _CHANNEL_STDIN_WAKE_PROMPTS.pop(channel_inflight_id, None)
                    _channel_stdin_clear_wake_claim(channel_inflight_id)
                    router_log(
                        "INFO",
                        f"channel_windows_console_confirmed message_id={channel_inflight_id} cursor={channel_inflight_cursor or '-'}",
                    )
                    channel_inflight_id = None
                    channel_inflight_cursor = None
                    channel_inflight_started_at = 0.0
                    channel_submit_attempts = 0
                    channel_last_submit_at = 0.0
                    channel_pending_recheck = True
                elif (
                    channel_inflight_state == "missing"
                    and channel_inflight_started_at > 0
                    and now - channel_inflight_started_at >= _channel_stdin_unseen_retry_seconds()
                ):
                    with _CHANNEL_STDIN_WAKE_LOCK:
                        _CHANNEL_STDIN_WAKE_DELIVERED.discard(channel_inflight_id)
                        _CHANNEL_STDIN_WAKE_PROMPTS.pop(channel_inflight_id, None)
                    _channel_stdin_clear_wake_claim(channel_inflight_id)
                    router_log(
                        "WARN",
                        f"channel_windows_console_unseen_retry message_id={channel_inflight_id} age={now - channel_inflight_started_at:.1f}s",
                    )
                    channel_inflight_id = None
                    channel_inflight_cursor = None
                    channel_inflight_started_at = 0.0
                    channel_submit_attempts = 0
                    channel_last_submit_at = 0.0
                    channel_pending_recheck = True
                    last_id = ensure_channel_llm_delivery_cursor_initialized()
                    channel_inflight_logged_at = now
                elif _channel_stdin_inflight_is_stale(channel_inflight_state, channel_inflight_started_at, now):
                    with _CHANNEL_STDIN_WAKE_LOCK:
                        _CHANNEL_STDIN_WAKE_DELIVERED.discard(channel_inflight_id)
                        _CHANNEL_STDIN_WAKE_PROMPTS.pop(channel_inflight_id, None)
                    _channel_stdin_clear_wake_claim(channel_inflight_id)
                    router_log(
                        "WARN",
                        "channel_windows_console_stale_inflight_retry "
                        f"message_id={channel_inflight_id} state={channel_inflight_state} "
                        f"age={now - channel_inflight_started_at:.1f}s cursor={channel_inflight_cursor or '-'}",
                    )
                    channel_inflight_id = None
                    channel_inflight_cursor = None
                    channel_inflight_started_at = 0.0
                    channel_submit_attempts = 0
                    channel_last_submit_at = 0.0
                    channel_pending_recheck = True
                    last_id = ensure_channel_llm_delivery_cursor_initialized()
                    channel_inflight_logged_at = now
                elif now - channel_inflight_logged_at >= 30.0:
                    channel_inflight_logged_at = now
                    router_log(
                        "INFO",
                        f"channel_windows_console_waiting_for_turn_completion message_id={channel_inflight_id} state={channel_inflight_state}",
                    )
            if now >= channel_input_ready_at and now - last_compact_poll >= 0.5:
                last_compact_poll = now
                if channel_inflight_id is None:
                    log_defer = now - compact_defer_logged_at >= 30.0
                    compact_status = _inject_pending_compact_request(
                        writer,
                        channel_enter_bytes,
                        log_defer=log_defer,
                        submit_retry_count=submit_retry_count,
                        confirm_submit=channel_wake_confirm_submit,
                        bracketed_paste=windows_bracketed_paste,
                        submit_delay_seconds=channel_wake_submit_delay_seconds,
                    )
                    if compact_status == "deferred" and log_defer:
                        compact_defer_logged_at = now
                    elif compact_status == "injected":
                        compact_defer_logged_at = 0.0
            if now >= channel_input_ready_at and now - last_channel_poll >= 0.5:
                last_channel_poll = now
                marker = _chat_messages_file_marker()
                if inject_channel_messages and _channel_stdin_should_check_pending(
                    marker,
                    last_channel_marker,
                    channel_pending_recheck,
                    channel_inflight_id,
                ):
                    if _channel_stdin_active_tool_call() or _channel_stdin_active_turn():
                        channel_pending_recheck = True
                        if now - channel_tool_defer_logged_at >= 30.0:
                            channel_tool_defer_logged_at = now
                            router_log("INFO", f"channel_windows_console_deferred cursor={last_id} reason=active_turn")
                    else:
                        if marker != last_channel_marker:
                            last_channel_marker = marker
                        channel_pending_recheck = False
                        last_id = max(last_id, ensure_channel_llm_delivery_cursor_initialized())
                        injected_ids: list[int] = []
                        last_id = _inject_pending_channel_messages(
                            writer,
                            last_id,
                            channel_enter_bytes,
                            web_chat_only=inject_web_chat_only,
                            wake_for_llm_delivery=wake_for_llm_delivery,
                            commit_cursor=False,
                            injected_message_ids=injected_ids,
                            submit_retry_count=submit_retry_count,
                            confirm_submit=channel_wake_confirm_submit,
                            bracketed_paste=windows_bracketed_paste,
                            submit_delay_seconds=channel_wake_submit_delay_seconds,
                            skip_blocking_wake_states=channel_inflight_id is not None,
                        )
                        if injected_ids:
                            channel_inflight_id = injected_ids[-1]
                            channel_inflight_cursor = last_id
                            channel_inflight_logged_at = now
                            channel_inflight_started_at = now
                            channel_submit_attempts = 1
                            channel_last_submit_at = now
            time.sleep(0.05)
        return proc.wait()
    finally:
        _write_terminal_input_mode_reset()
        input_mode_guard.restore()
        _terminate_recorded_child_process(proc, "current Codex")
        _release_codex_child_process_record(tracked_child_pid_path, proc.pid)


def subprocess_call_with_channel_wake_proxy(
    cmd: list[str],
    env: dict[str, str],
    *,
    inject_channel_messages: bool = True,
    inject_web_chat_only: bool = False,
    wake_for_llm_delivery: bool = False,
    synthetic_enter_bytes: str | bytes | None = None,
    normalize_bare_cr_for_synthetic_enter: bool = True,
    channel_wake_submit_retries: int = 1,
    channel_wake_confirm_submit: bool = False,
    channel_wake_bracketed_paste: bool = False,
    channel_wake_submit_delay_seconds: float | None = None,
    tracked_child_pid_path: Path | None = None,
) -> int:
    if os.name == "nt" and _windows_console_input_supported():
        try:
            return subprocess_call_with_windows_console_wake_proxy(
                cmd,
                env,
                inject_channel_messages=inject_channel_messages,
                inject_web_chat_only=inject_web_chat_only,
                wake_for_llm_delivery=wake_for_llm_delivery,
                synthetic_enter_bytes=synthetic_enter_bytes,
                normalize_bare_cr_for_synthetic_enter=normalize_bare_cr_for_synthetic_enter,
                channel_wake_submit_retries=channel_wake_submit_retries,
                channel_wake_confirm_submit=channel_wake_confirm_submit,
                channel_wake_bracketed_paste=channel_wake_bracketed_paste,
                channel_wake_submit_delay_seconds=channel_wake_submit_delay_seconds,
                tracked_child_pid_path=tracked_child_pid_path,
            )
        except Exception as exc:
            router_log(
                "WARN",
                f"channel_windows_console_proxy_failed error={type(exc).__name__}: {exc}; using direct subprocess call",
            )
    if os.name != "posix" or not sys.stdin.isatty() or not sys.stdout.isatty():
        router_log("INFO", "channel_stdin_proxy_unavailable; using direct subprocess call")
        if tracked_child_pid_path is None:
            return subprocess.call(cmd, env=env)
        proc = subprocess.Popen(cmd, env=env)
        _write_codex_child_process_record(tracked_child_pid_path, proc.pid, cmd)
        try:
            return proc.wait()
        finally:
            _terminate_recorded_child_process(proc, "current Codex")
            _release_codex_child_process_record(tracked_child_pid_path, proc.pid)
    import pty
    import select
    import termios
    import tty

    last_id = ensure_channel_llm_delivery_cursor_initialized()
    last_channel_marker: tuple[float, int] = (0.0, -1)
    master_fd, slave_fd = pty.openpty()
    stdout_fd = sys.stdout.fileno()
    rows, cols = _terminal_winsize_from_fd(stdout_fd)
    if _apply_pty_winsize(slave_fd, rows, cols):
        router_log("INFO", f"channel_stdin_proxy_winsize_init rows={rows} cols={cols}")
    proc = subprocess.Popen(cmd, stdin=slave_fd, stdout=slave_fd, stderr=slave_fd, env=env, close_fds=True)
    _write_codex_child_process_record(tracked_child_pid_path, proc.pid, cmd)
    os.close(slave_fd)
    stdin_fd = sys.stdin.fileno()
    old_attrs = termios.tcgetattr(stdin_fd)
    old_sigwinch = None
    sigwinch_installed = False
    mouse_input_filter = _TerminalMouseInputFilter()
    last_channel_poll = 0.0
    last_compact_poll = 0.0
    channel_inflight_id: int | None = None
    channel_inflight_cursor: int | None = None
    channel_inflight_logged_at = 0.0
    channel_inflight_started_at = 0.0
    channel_pending_recheck = False
    channel_tool_defer_logged_at = 0.0
    compact_defer_logged_at = 0.0
    channel_enter_bytes = _channel_wake_enter_bytes(synthetic_enter_bytes)
    submit_retry_count = max(1, min(8, int(channel_wake_submit_retries or 1)))
    router_log(
        "INFO",
        "channel_stdin_proxy_enter_default "
        f"enter={_channel_enter_label(channel_enter_bytes)} os={os.name} platform={sys.platform} "
        f"submit_retries={submit_retry_count} confirm_submit={bool(channel_wake_confirm_submit)} "
        f"bracketed_paste={bool(channel_wake_bracketed_paste)}",
    )
    _write_terminal_input_mode_reset()

    def _handle_sigwinch(signum: int, frame: Any) -> None:
        new_rows, new_cols = _terminal_winsize_from_fd(stdout_fd)
        if _apply_pty_winsize(master_fd, new_rows, new_cols):
            router_log("INFO", f"channel_stdin_proxy_winsize_resize rows={new_rows} cols={new_cols}")
        if callable(old_sigwinch):
            old_sigwinch(signum, frame)

    try:
        try:
            old_sigwinch = signal.getsignal(signal.SIGWINCH)
            signal.signal(signal.SIGWINCH, _handle_sigwinch)
            sigwinch_installed = True
        except Exception:
            sigwinch_installed = False
        tty.setraw(stdin_fd)
        while proc.poll() is None:
            try:
                readable, _, _ = select.select([stdin_fd, master_fd], [], [], 0.2)
            except OSError:
                break
            if stdin_fd in readable:
                data = os.read(stdin_fd, 4096)
                if data:
                    filtered_data = mouse_input_filter.feed(data)
                    if filtered_data:
                        observed_enter = _channel_synthetic_enter_bytes_from_user_input(
                            filtered_data,
                            normalize_bare_cr=normalize_bare_cr_for_synthetic_enter,
                        )
                        if observed_enter and not _channel_wake_enter_env_is_fixed():
                            if observed_enter != channel_enter_bytes:
                                router_log(
                                    "INFO",
                                    f"channel_stdin_proxy_enter_observed enter={_channel_enter_label(observed_enter)}",
                                )
                            channel_enter_bytes = observed_enter
                        _write_fd_all(master_fd, filtered_data)
            if master_fd in readable:
                try:
                    data = os.read(master_fd, 4096)
                except OSError:
                    break
                if data:
                    _write_fd_all(stdout_fd, data)
            now = time.time()
            if channel_inflight_id is not None:
                channel_inflight_state = _channel_stdin_wake_state(channel_inflight_id)
                if channel_inflight_state == "completed":
                    if channel_inflight_cursor is not None:
                        _commit_channel_llm_cursor_if_newer(channel_inflight_cursor)
                    with _CHANNEL_STDIN_WAKE_LOCK:
                        _CHANNEL_STDIN_WAKE_PROMPTS.pop(channel_inflight_id, None)
                    _channel_stdin_clear_wake_claim(channel_inflight_id)
                    router_log(
                        "INFO",
                        f"channel_stdin_proxy_confirmed message_id={channel_inflight_id} cursor={channel_inflight_cursor or '-'}",
                    )
                    channel_inflight_id = None
                    channel_inflight_cursor = None
                    channel_inflight_started_at = 0.0
                    channel_pending_recheck = True
                elif (
                    channel_inflight_state == "missing"
                    and channel_inflight_started_at > 0
                    and now - channel_inflight_started_at >= _channel_stdin_unseen_retry_seconds()
                ):
                    with _CHANNEL_STDIN_WAKE_LOCK:
                        _CHANNEL_STDIN_WAKE_DELIVERED.discard(channel_inflight_id)
                        _CHANNEL_STDIN_WAKE_PROMPTS.pop(channel_inflight_id, None)
                    _channel_stdin_clear_wake_claim(channel_inflight_id)
                    router_log(
                        "WARN",
                        f"channel_stdin_proxy_unseen_retry message_id={channel_inflight_id} age={now - channel_inflight_started_at:.1f}s",
                    )
                    channel_inflight_id = None
                    channel_inflight_cursor = None
                    channel_inflight_started_at = 0.0
                    channel_pending_recheck = True
                    last_id = ensure_channel_llm_delivery_cursor_initialized()
                    channel_inflight_logged_at = now
                elif _channel_stdin_inflight_is_stale(channel_inflight_state, channel_inflight_started_at, now):
                    if channel_inflight_cursor is not None:
                        _commit_channel_llm_cursor_if_newer(channel_inflight_cursor)
                    with _CHANNEL_STDIN_WAKE_LOCK:
                        _CHANNEL_STDIN_WAKE_DELIVERED.discard(channel_inflight_id)
                        _CHANNEL_STDIN_WAKE_PROMPTS.pop(channel_inflight_id, None)
                    _channel_stdin_clear_wake_claim(channel_inflight_id)
                    router_log(
                        "WARN",
                        "channel_stdin_proxy_stale_inflight_skipped "
                        f"message_id={channel_inflight_id} state={channel_inflight_state} "
                        f"age={now - channel_inflight_started_at:.1f}s cursor={channel_inflight_cursor or '-'}",
                    )
                    channel_inflight_id = None
                    channel_inflight_cursor = None
                    channel_inflight_started_at = 0.0
                    channel_pending_recheck = True
                    last_id = ensure_channel_llm_delivery_cursor_initialized()
                    channel_inflight_logged_at = now
                elif now - channel_inflight_logged_at >= 30.0:
                    channel_inflight_logged_at = now
                    router_log(
                        "INFO",
                        f"channel_stdin_proxy_waiting_for_turn_completion message_id={channel_inflight_id} state={channel_inflight_state}",
                    )
            if now - last_compact_poll >= 0.5:
                last_compact_poll = now
                if channel_inflight_id is None:
                    log_defer = now - compact_defer_logged_at >= 30.0
                    compact_status = _inject_pending_compact_request(
                        master_fd,
                        channel_enter_bytes,
                        log_defer=log_defer,
                        submit_retry_count=submit_retry_count,
                        confirm_submit=channel_wake_confirm_submit,
                        bracketed_paste=channel_wake_bracketed_paste,
                        submit_delay_seconds=channel_wake_submit_delay_seconds,
                    )
                    if compact_status == "deferred" and log_defer:
                        compact_defer_logged_at = now
                    elif compact_status == "injected":
                        compact_defer_logged_at = 0.0
            if now - last_channel_poll >= 0.5:
                last_channel_poll = now
                marker = _chat_messages_file_marker()
                if inject_channel_messages and _channel_stdin_should_check_pending(
                    marker,
                    last_channel_marker,
                    channel_pending_recheck,
                    channel_inflight_id,
                ):
                    if _channel_stdin_active_tool_call():
                        channel_pending_recheck = True
                        if now - channel_tool_defer_logged_at >= 30.0:
                            channel_tool_defer_logged_at = now
                            router_log("INFO", f"channel_stdin_proxy_deferred cursor={last_id} reason=active_tool_call")
                    else:
                        if marker != last_channel_marker:
                            last_channel_marker = marker
                        channel_pending_recheck = False
                        last_id = max(last_id, ensure_channel_llm_delivery_cursor_initialized())
                        injected_ids: list[int] = []
                        last_id = _inject_pending_channel_messages(
                            master_fd,
                            last_id,
                            channel_enter_bytes,
                            web_chat_only=inject_web_chat_only,
                            wake_for_llm_delivery=wake_for_llm_delivery,
                            commit_cursor=False,
                            injected_message_ids=injected_ids,
                            submit_retry_count=submit_retry_count,
                            confirm_submit=channel_wake_confirm_submit,
                            bracketed_paste=channel_wake_bracketed_paste,
                            submit_delay_seconds=channel_wake_submit_delay_seconds,
                            skip_blocking_wake_states=channel_inflight_id is not None,
                        )
                        if injected_ids:
                            channel_inflight_id = injected_ids[-1]
                            channel_inflight_cursor = last_id
                            channel_inflight_logged_at = now
                            channel_inflight_started_at = now
        while True:
            try:
                readable, _, _ = select.select([master_fd], [], [], 0)
                if master_fd not in readable:
                    break
                data = os.read(master_fd, 4096)
                if not data:
                    break
                _write_fd_all(stdout_fd, data)
            except OSError:
                break
        return proc.returncode if proc.returncode is not None else 0
    finally:
        if sigwinch_installed:
            try:
                signal.signal(signal.SIGWINCH, old_sigwinch)
            except (OSError, ValueError) as exc:
                router_log("WARN", f"channel_sigwinch_restore_failed error={type(exc).__name__}: {exc}")
        try:
            termios.tcsetattr(stdin_fd, termios.TCSADRAIN, old_attrs)
        except Exception as exc:
            router_log("WARN", f"channel_terminal_restore_failed error={type(exc).__name__}: {exc}")
        _write_terminal_input_mode_reset()
        try:
            os.close(master_fd)
        except Exception as exc:
            router_log("WARN", f"channel_pty_close_failed error={type(exc).__name__}: {exc}")
        _terminate_recorded_child_process(proc, "current Codex")
        _release_codex_child_process_record(tracked_child_pid_path, proc.pid)


def subprocess_call_with_child_pid_record(cmd: list[str], env: dict[str, str], pid_path: Path | None = None) -> int:
    if pid_path is None:
        return subprocess.call(cmd, env=env)
    proc = subprocess.Popen(cmd, env=env)
    _write_codex_child_process_record(pid_path, proc.pid, cmd)
    try:
        return proc.wait()
    finally:
        _terminate_recorded_child_process(proc, "current Codex")
        _release_codex_child_process_record(pid_path, proc.pid)


def _mcp_proxy_notification_payload(server_name: str, message: dict[str, Any]) -> dict[str, Any] | None:
    method = str(message.get("method") or "").strip()
    if not method.startswith("notifications/"):
        return None
    params = message.get("params") if isinstance(message.get("params"), dict) else {}
    payload = params.get("payload") if isinstance(params.get("payload"), dict) else {}
    data = params.get("data") if isinstance(params.get("data"), dict) else {}
    event = params.get("event") if isinstance(params.get("event"), dict) else {}
    meta: dict[str, Any] = {
        "mcp_server": server_name,
        "mcp_method": method,
        "mcp_json": _json_safe_metadata(message),
    }
    if message.get("jsonrpc") is not None:
        meta["jsonrpc"] = message.get("jsonrpc")
    if message.get("id") is not None:
        meta["rpc_id"] = message.get("id")
    meta.update(_event_meta_from_sources(message, params, payload, data, event))
    content = (
        _event_payload_text(params)
        or _event_payload_text(payload)
        or _event_payload_text(data)
        or _event_payload_text(event)
    )
    if not content and params:
        content = json.dumps(params, ensure_ascii=False, separators=(",", ":"), default=str)
    if not content:
        return None
    raw_message = _pretty_json_value(message)
    channel = str(meta.get("channel") or meta.get("room_id") or meta.get("room") or server_name)
    return {
        "channel": channel,
        "sender_id": str(meta.get("sender_id") or meta.get("agent_id") or server_name),
        "recipients": meta.get("recipient_id") or "all",
        "thread_id": meta.get("thread_id"),
        "parent_id": meta.get("parent_id"),
        "kind": method.replace("notifications/claude/", "").replace("notifications/", "").replace("/", "."),
        "message": raw_message,
        "meta": meta,
    }


def _mcp_proxy_stable_event_identity(chat_payload: dict[str, Any]) -> tuple[str, str] | None:
    meta = chat_payload.get("meta") if isinstance(chat_payload.get("meta"), dict) else {}
    for key in (
        "stream_id",
        "sse_id",
        "message_id",
        "source_message_id",
        "event_id",
        "cursor",
        "assignment_id",
        "poll_id",
        "task_id",
        "sequence",
        "seq",
    ):
        value = meta.get(key)
        if value is not None and str(value).strip():
            return key, str(value).strip()
    return None


def _mcp_proxy_notification_dedupe_key(server_name: str, chat_payload: dict[str, Any]) -> tuple[str, bool]:
    meta = chat_payload.get("meta") if isinstance(chat_payload.get("meta"), dict) else {}
    body_source = (
        _notification_semantic_text_from_envelope(meta.get("mcp_json"))
        or _notification_semantic_text_from_envelope(meta.get("sse_json"))
        or str(chat_payload.get("message") or "")
    )
    body = re.sub(r"\s+", " ", body_source).strip()
    room = str(meta.get("room_id") or meta.get("room") or chat_payload.get("channel") or server_name)
    kind = str(meta.get("kind") or chat_payload.get("kind") or "")
    stable_identity = _mcp_proxy_stable_event_identity(chat_payload)
    if stable_identity:
        stable_key, stable_value = stable_identity
        return (
            json.dumps(
                ["stable", room, kind, stable_key, stable_value],
                ensure_ascii=False,
                separators=(",", ":"),
            ),
            True,
        )
    sender = str(chat_payload.get("sender_id") or meta.get("sender_id") or meta.get("agent_id") or server_name)
    thread = str(chat_payload.get("thread_id") or meta.get("thread_id") or "")
    parent = str(chat_payload.get("parent_id") or meta.get("parent_id") or "")
    return json.dumps(
        [server_name, room, sender, thread, parent, body],
        ensure_ascii=False,
        separators=(",", ":"),
    ), False


def _mcp_proxy_should_skip_duplicate_notification(server_name: str, chat_payload: dict[str, Any]) -> tuple[bool, str | None]:
    meta = chat_payload.get("meta") if isinstance(chat_payload.get("meta"), dict) else {}
    method = str(meta.get("mcp_method") or "")
    if not method.startswith("notifications/"):
        return False, None
    key, has_stable_identity = _mcp_proxy_notification_dedupe_key(server_name, chat_payload)
    now = time.time()
    with _MCP_NOTIFICATION_DEDUP_LOCK:
        stale = [
            item_key
            for item_key, (_, seen_at) in _MCP_NOTIFICATION_DEDUP_RECENT.items()
            if now - seen_at > _MCP_NOTIFICATION_DEDUP_TTL_SECONDS
        ]
        for item_key in stale:
            _MCP_NOTIFICATION_DEDUP_RECENT.pop(item_key, None)
        previous = _MCP_NOTIFICATION_DEDUP_RECENT.get(key)
        _MCP_NOTIFICATION_DEDUP_RECENT[key] = (method, now)
    if not previous:
        return False, None
    previous_method, previous_seen_at = previous
    if has_stable_identity and now - previous_seen_at <= _MCP_NOTIFICATION_DEDUP_TTL_SECONDS:
        return True, previous_method
    is_native_pair = _NATIVE_CHANNEL_NOTIFICATION_METHOD in {previous_method, method}
    if previous_method != method and is_native_pair and now - previous_seen_at <= _MCP_NOTIFICATION_DEDUP_TTL_SECONDS:
        return True, previous_method
    return False, None


def _mcp_proxy_observe_json_message(server_name: str, payload: Any, *, schedule_direct: bool = True) -> dict[str, Any] | None:
    if not isinstance(payload, dict):
        return None
    chat_payload = _mcp_proxy_notification_payload(server_name, payload)
    if not chat_payload:
        return None
    skip_duplicate, previous_method = _mcp_proxy_should_skip_duplicate_notification(server_name, chat_payload)
    if skip_duplicate:
        router_log(
            "INFO",
            f"mcp_proxy_notification_skipped_duplicate server={server_name} method={payload.get('method')} previous_method={previous_method}",
        )
        return None
    try:
        saved = append_chat_message(chat_payload)
        if saved.get("_ciel_runtime_duplicate"):
            router_log(
                "INFO",
                f"mcp_proxy_notification_skipped_duplicate_persisted server={server_name} method={payload.get('method')} existing_id={saved.get('id')}",
            )
            return saved
        router_log(
            "INFO",
            f"mcp_proxy_notification server={server_name} method={payload.get('method')} message_id={saved.get('id')}",
        )
        return saved
    except Exception as exc:
        router_log("WARN", f"mcp_proxy_notification_failed server={server_name} error={type(exc).__name__}: {exc}")
    return None


class _McpStdoutObserver(McpStdoutObserver):
    def __init__(self, server_name: str) -> None:
        super().__init__(server_name, _mcp_proxy_observe_json_message)


