CODEX_TUI_ALTERNATE_SCREEN_KEY = "tui.alternate_screen"


def toml_string(value: str) -> str:
    return json.dumps(str(value))


def _codex_config_override_keys(passthrough: list[str]) -> set[str]:
    keys: set[str] = set()
    i = 0
    while i < len(passthrough):
        arg = str(passthrough[i])
        value = ""
        if arg in ("-c", "--config") and i + 1 < len(passthrough):
            value = str(passthrough[i + 1])
            i += 2
        elif arg.startswith("--config="):
            value = arg.split("=", 1)[1]
            i += 1
        else:
            i += 1
            continue
        if "=" in value:
            keys.add(value.split("=", 1)[0].strip())
    return keys


def _toml_scalar_without_comment(raw: str) -> str:
    in_single = False
    in_double = False
    escaped = False
    out: list[str] = []
    for ch in raw:
        if escaped:
            out.append(ch)
            escaped = False
            continue
        if ch == "\\" and in_double:
            out.append(ch)
            escaped = True
            continue
        if ch == '"' and not in_single:
            in_double = not in_double
        elif ch == "'" and not in_double:
            in_single = not in_single
        elif ch == "#" and not in_single and not in_double:
            break
        out.append(ch)
    return "".join(out).strip()


def _unquote_toml_string(raw: str) -> str:
    value = raw.strip()
    if len(value) >= 2 and value[0] == value[-1] and value[0] in ("'", '"'):
        return value[1:-1].strip()
    return value


def codex_alternate_screen_value_from_config_text(text: str) -> str | None:
    table = ""
    for line in text.splitlines():
        stripped = _toml_scalar_without_comment(line)
        if not stripped:
            continue
        table_match = re.fullmatch(r"\[([A-Za-z0-9_.-]+)\]", stripped)
        if table_match:
            table = table_match.group(1).strip()
            continue
        match = None
        if table == "tui":
            match = re.match(r"alternate_screen\s*=\s*(.+)$", stripped)
        if match is None:
            match = re.match(r"tui\.alternate_screen\s*=\s*(.+)$", stripped)
        if match is None:
            continue
        value = _unquote_toml_string(match.group(1)).casefold()
        if value in ("false", "0", "off", "no", "disabled", "disable"):
            return "never"
        if value in ("true", "1", "on", "yes", "enabled", "enable"):
            return "always"
        if value in ("auto", "always", "never"):
            return None
        return "auto"
    return None


def codex_config_paths_for_launch(passthrough: list[str], env: dict[str, str] | None = None, cwd: Path | None = None) -> list[Path]:
    env = env or os.environ
    home = Path(env.get("CODEX_HOME") or (Path.home() / ".codex")).expanduser()
    paths = [home / "config.toml"]
    profiles = []
    i = 0
    while i < len(passthrough):
        arg = str(passthrough[i])
        if arg in ("-p", "--profile") and i + 1 < len(passthrough):
            profiles.append(str(passthrough[i + 1]))
            i += 2
            continue
        if arg.startswith("--profile="):
            profiles.append(arg.split("=", 1)[1])
        i += 1
    for profile in profiles:
        if re.fullmatch(r"[A-Za-z0-9_-]+", profile or ""):
            paths.append(home / f"{profile}.config.toml")
    current = (cwd or Path.cwd()).resolve()
    for parent in (current, *current.parents):
        path = parent / ".codex" / "config.toml"
        if path not in paths:
            paths.append(path)
    return paths


def _normalize_codex_mcp_server(raw_name: Any, raw_server: Any) -> tuple[str, dict[str, Any]] | None:
    name = str(raw_name or "").strip()
    if not name or not isinstance(raw_server, dict):
        return None
    url = str(raw_server.get("url") or raw_server.get("endpoint") or "").strip()
    if not url.startswith(("http://", "https://")):
        return None
    explicit_type = raw_server.get("type") is not None or raw_server.get("transport") is not None
    server_type = str(raw_server.get("type") or raw_server.get("transport") or "http").strip().lower()
    if server_type in {"streamable-http", "streamable_http"}:
        server_type = "http"
    if server_type not in {"http", "sse"}:
        server_type = "http"
    out: dict[str, Any] = {
        "type": server_type,
        "url": url,
    }
    if explicit_type:
        out["_ciel_runtime_explicit_type"] = True
    for key in (
        "headers",
        "env_http_headers",
        "bearer_token_env_var",
        "token_env_var",
        "bearer_token",
        "token",
        "streamable_requires_session",
        "require_session",
        "mcp_session_required",
        "mcp_protocol_version",
        "protocolVersion",
        "protocol_version",
        "mcp_timeout_seconds",
        "timeout",
    ):
        value = raw_server.get(key)
        if value is not None:
            out[key] = value
    return name, out


def _codex_mcp_servers_from_toml_data(data: Any) -> dict[str, dict[str, Any]]:
    if not isinstance(data, dict):
        return {}
    servers = data.get("mcp_servers")
    if not isinstance(servers, dict):
        return {}
    out: dict[str, dict[str, Any]] = {}
    for raw_name, raw_server in servers.items():
        normalized = _normalize_codex_mcp_server(raw_name, raw_server)
        if normalized is None:
            continue
        name, server = normalized
        out[name] = server
    return out


def _toml_table_parts(raw: str) -> list[str]:
    parts: list[str] = []
    current: list[str] = []
    quote = ""
    escaped = False
    for ch in raw:
        if escaped:
            current.append(ch)
            escaped = False
            continue
        if ch == "\\" and quote == '"':
            current.append(ch)
            escaped = True
            continue
        if ch in {"'", '"'}:
            if quote == ch:
                quote = ""
            elif not quote:
                quote = ch
            current.append(ch)
            continue
        if ch == "." and not quote:
            part = _unquote_toml_string("".join(current).strip())
            if part:
                parts.append(part)
            current = []
            continue
        current.append(ch)
    part = _unquote_toml_string("".join(current).strip())
    if part:
        parts.append(part)
    return parts


def _parse_simple_toml_value(raw: str) -> Any:
    value = _toml_scalar_without_comment(raw).strip()
    if not value:
        return ""
    if len(value) >= 2 and value[0] == value[-1] and value[0] in {"'", '"'}:
        return _unquote_toml_string(value)
    low = value.lower()
    if low in {"true", "false"}:
        return low == "true"
    if value.startswith("[") and value.endswith("]"):
        items: list[str] = []
        body = value[1:-1]
        current: list[str] = []
        quote = ""
        escaped = False
        for ch in body:
            if escaped:
                current.append(ch)
                escaped = False
                continue
            if ch == "\\" and quote == '"':
                current.append(ch)
                escaped = True
                continue
            if ch in {"'", '"'}:
                if quote == ch:
                    quote = ""
                elif not quote:
                    quote = ch
                current.append(ch)
                continue
            if ch == "," and not quote:
                item = _unquote_toml_string("".join(current).strip())
                if item:
                    items.append(item)
                current = []
                continue
            current.append(ch)
        item = _unquote_toml_string("".join(current).strip())
        if item:
            items.append(item)
        return items
    try:
        return int(value)
    except ValueError:
        return value


def _fallback_codex_mcp_servers_from_config_text(text: str) -> dict[str, dict[str, Any]]:
    raw_servers: dict[str, dict[str, Any]] = {}
    current_name = ""
    current_subtable = ""
    for line in text.splitlines():
        stripped = _toml_scalar_without_comment(line)
        if not stripped:
            continue
        table_match = re.fullmatch(r"\[(.+)\]", stripped)
        if table_match:
            parts = _toml_table_parts(table_match.group(1).strip())
            current_name = ""
            current_subtable = ""
            if len(parts) >= 2 and parts[0] == "mcp_servers":
                current_name = parts[1]
                current_subtable = parts[2] if len(parts) >= 3 else ""
                raw_servers.setdefault(current_name, {})
            continue
        if not current_name or "=" not in stripped:
            continue
        key, raw_value = stripped.split("=", 1)
        key = key.strip()
        value = _parse_simple_toml_value(raw_value)
        server = raw_servers.setdefault(current_name, {})
        if current_subtable:
            nested = server.setdefault(current_subtable, {})
            if isinstance(nested, dict):
                nested[key] = value
            continue
        server[key] = value
    return _codex_mcp_servers_from_toml_data({"mcp_servers": raw_servers})


def codex_mcp_servers_from_config_text(text: str) -> dict[str, dict[str, Any]]:
    try:
        import tomllib  # type: ignore[import-not-found]
        data = tomllib.loads(text)
        parsed = _codex_mcp_servers_from_toml_data(data)
        if parsed:
            return parsed
    except Exception:
        pass
    return _fallback_codex_mcp_servers_from_config_text(text)


def discovered_codex_mcp_servers(
    passthrough: list[str] | None = None,
    env: dict[str, str] | None = None,
    cwd: Path | None = None,
) -> dict[str, dict[str, Any]]:
    servers: dict[str, dict[str, Any]] = {}
    for path in codex_config_paths_for_launch(passthrough or [], env=env, cwd=cwd):
        if not path.exists() or not path.is_file():
            continue
        try:
            parsed = codex_mcp_servers_from_config_text(path.read_text(encoding="utf-8"))
        except Exception as exc:
            router_log("WARN", f"codex_mcp_config_read_failed path={path} error={type(exc).__name__}: {exc}")
            continue
        for name, server in parsed.items():
            servers[name] = server
    return servers


def write_codex_mcp_config_for_channel_discovery(
    passthrough: list[str] | None = None,
    env: dict[str, str] | None = None,
    cwd: Path | None = None,
) -> Path | None:
    servers = discovered_codex_mcp_servers(passthrough or [], env=env, cwd=cwd)
    if not servers:
        try:
            CODEX_MCP_CONFIG.unlink()
        except FileNotFoundError:
            pass
        except Exception as exc:
            router_log("WARN", f"codex_mcp_config_remove_failed error={type(exc).__name__}: {exc}")
        return None
    CONFIG_DIR.mkdir(parents=True, exist_ok=True)
    CODEX_MCP_CONFIG.write_text(json.dumps({"mcpServers": servers}, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    try:
        os.chmod(CODEX_MCP_CONFIG, 0o600)
    except Exception:
        pass
    router_log("INFO", f"codex_mcp_config_written servers={','.join(sorted(servers))}")
    return CODEX_MCP_CONFIG


def _codex_config_bare_key(name: str) -> str | None:
    text = str(name or "").strip()
    if re.fullmatch(r"[A-Za-z0-9_-]+", text):
        return text
    return None


def codex_channel_capable_mcp_server_names(cfg: dict[str, Any], codex_mcp_config: Path | None) -> list[str]:
    if not codex_mcp_config or not codex_mcp_config.exists() or not codex_mcp_config.is_file():
        return []
    extra_paths: list[Path | str] = [codex_mcp_config]
    ensure_channel_probe_cache_for_launch(cfg, [], extra_config_paths=extra_paths)
    candidate_names = [
        str(server.get("channel") or "").strip()
        for server in _read_mcp_sse_servers_from_json(codex_mcp_config, Path.cwd())
        if str(server.get("channel") or "").strip()
    ]
    source_key = _path_for_compare(codex_mcp_config)
    capable = {
        str(record.get("name") or "").strip()
        for record in cached_channel_probe_servers()
        if record.get("capable")
        and str(record.get("name") or "").strip()
        and _path_for_compare(Path(str(record.get("source_path") or ""))) == source_key
    }
    names = [
        name
        for name in candidate_names
        if name in capable and name.strip().lower() not in _NATIVE_ROUTER_CHANNEL_NAMES
    ]
    return _dedupe_strings(names)


def codex_streamable_http_mcp_servers(codex_mcp_config: Path | None) -> dict[str, dict[str, Any]]:
    if not codex_mcp_config or not codex_mcp_config.exists() or not codex_mcp_config.is_file():
        return {}
    try:
        data = json.loads(codex_mcp_config.read_text(encoding="utf-8"))
    except Exception as exc:
        router_log("WARN", f"codex_mcp_compat_source_read_failed error={type(exc).__name__}: {exc}")
        return {}
    servers = data.get("mcpServers") if isinstance(data, dict) else None
    if not isinstance(servers, dict):
        return {}
    out: dict[str, dict[str, Any]] = {}
    for raw_name, raw_server in servers.items():
        name = str(raw_name).strip()
        if name and isinstance(raw_server, dict) and _mcp_server_is_streamable_http(raw_server):
            out[name] = raw_server
    return out


def codex_mcp_native_http_compat_args(
    codex_mcp_config: Path | None,
    *,
    split_http_proxy: bool = False,
    channel_owned_server_names: Iterable[str] | None = None,
) -> list[str]:
    servers = codex_streamable_http_mcp_servers(codex_mcp_config)
    if not servers:
        return []
    args: list[str] = []
    active: list[str] = []
    channel_owned = {
        _channel_sse_public_mcp_name(str(name or "").strip())
        for name in channel_owned_server_names or []
        if str(name or "").strip()
    }
    for name, server in sorted(servers.items()):
        key = _codex_config_bare_key(name)
        if not key:
            router_log("WARN", f"codex_mcp_compat_skipped_unsafe_name server={name}")
            continue
        if split_http_proxy or _channel_sse_public_mcp_name(name) in channel_owned:
            args.extend(["-c", f"mcp_servers.{key}.url={toml_string(codex_mcp_split_proxy_url(name))}"])
        active.append(name)
    if active:
        router_log(
            "INFO",
            "codex_mcp_native_http_compat servers=%s split_http_proxy=%s"
            % (",".join(active), str(bool(split_http_proxy)).lower()),
        )
    return args


def codex_alternate_screen_compat_args(passthrough: list[str], env: dict[str, str] | None = None, cwd: Path | None = None) -> list[str]:
    if has_passthrough_option(passthrough, "--no-alt-screen") or CODEX_TUI_ALTERNATE_SCREEN_KEY in _codex_config_override_keys(passthrough):
        return []
    for path in codex_config_paths_for_launch(passthrough, env=env, cwd=cwd):
        try:
            text = path.read_text(encoding="utf-8")
        except Exception:
            continue
        value = codex_alternate_screen_value_from_config_text(text)
        if value:
            router_log("WARN", f"codex_compat_alternate_screen_override path={path} value={value}")
            print(f'Ciel Runtime warning: applying Codex config compatibility override {CODEX_TUI_ALTERNATE_SCREEN_KEY}="{value}".', flush=True)
            return ["-c", f"{CODEX_TUI_ALTERNATE_SCREEN_KEY}={toml_string(value)}"]
    return []


def codex_runtime_config_args(router_base: str = ROUTER_BASE) -> list[str]:
    provider = CODEX_RUNTIME_PROVIDER_ID
    base = router_base.rstrip("/") + "/v1"
    return [
        "-c",
        f"model_provider={toml_string(provider)}",
        "-c",
        f"model_providers.{provider}.name={toml_string('Ciel Runtime')}",
        "-c",
        f"model_providers.{provider}.base_url={toml_string(base)}",
        "-c",
        f"model_providers.{provider}.wire_api={toml_string('responses')}",
        "-c",
        f"model_providers.{provider}.env_key={toml_string(CODEX_RUNTIME_API_KEY_ENV)}",
        "-c",
        f"model_providers.{provider}.request_max_retries=0",
        "-c",
        f"model_providers.{provider}.stream_max_retries=0",
    ]


def write_codex_runtime_model_catalog(codex: str, cfg: dict[str, Any]) -> Path | None:
    """Add the routed model alias to Codex's own version-matched model catalog."""
    provider, pcfg = get_current_provider(cfg)
    if native_codex_enabled(provider):
        return None
    alias = current_alias(cfg)
    if not alias:
        return None
    try:
        catalog_env = os.environ.copy()
        catalog_env["PATH"] = path_with_ciel_runtime_user_dirs(catalog_env)
        result = subprocess.run(
            [codex, "debug", "models", "--bundled"],
            capture_output=True,
            text=True,
            encoding="utf-8",
            errors="replace",
            timeout=15,
            check=False,
            env=catalog_env,
        )
        if result.returncode != 0:
            raise RuntimeError((result.stderr or result.stdout or f"exit {result.returncode}").strip())
        catalog = json.loads(result.stdout)
        models = catalog.get("models") if isinstance(catalog, dict) else None
        if not isinstance(models, list) or not models:
            raise ValueError("bundled catalog contains no models")
        template = next((item for item in models if isinstance(item, dict) and item.get("slug") == "gpt-5.2"), None)
        if template is None:
            template = next((item for item in models if isinstance(item, dict)), None)
        if template is None:
            raise ValueError("bundled catalog contains no model metadata")

        routed = json.loads(json.dumps(template))
        context_window = context_limit_for_status(provider, pcfg) or provider_model_context_capacity(provider, pcfg) or 272000
        routed.update({
            "slug": alias,
            "display_name": f"Ciel Runtime {PROVIDER_LABELS.get(provider, provider)}",
            "description": f"{PROVIDER_LABELS.get(provider, provider)} routed through Ciel Runtime.",
            "visibility": "none",
            "supported_in_api": True,
            "priority": 99,
            "context_window": context_window,
            "max_context_window": context_window,
            "auto_compact_token_limit": max(1, (context_window * 9) // 10),
        })
        effort = str(pcfg.get("effort_level") or "").strip().lower()
        if effort:
            routed["default_reasoning_level"] = effort
            supported = routed.get("supported_reasoning_levels")
            if not isinstance(supported, list):
                supported = []
            if not any(isinstance(item, dict) and item.get("effort") == effort for item in supported):
                supported.append({"effort": effort, "description": f"{effort.title()} reasoning effort"})
            routed["supported_reasoning_levels"] = supported
        models = [item for item in models if not (isinstance(item, dict) and item.get("slug") == alias)]
        models.append(routed)
        catalog["models"] = models
        CONFIG_DIR.mkdir(parents=True, exist_ok=True)
        catalog_path = CONFIG_DIR / "codex-model-catalog.json"
        temp_path = catalog_path.with_suffix(".json.tmp")
        temp_path.write_text(json.dumps(catalog, ensure_ascii=False), encoding="utf-8")
        temp_path.replace(catalog_path)
        return catalog_path
    except Exception as exc:
        router_log("WARN", f"codex_model_catalog_generation_failed error={type(exc).__name__}: {exc}")
        return None


def codex_runtime_model_catalog_args(codex: str, cfg: dict[str, Any]) -> list[str]:
    path = write_codex_runtime_model_catalog(codex, cfg)
    if path is None:
        return []
    return ["-c", f"model_catalog_json={toml_string(str(path.resolve()))}"]


